INSERT INTO `energy` VALUES (1,'Main Electrical Supply',1,'Primary electrical power for manufacturing',NULL),(2,'Compressed Air System',2,'Compressed air for pneumatic equipment',NULL),(3,'Electrical Energy',2,'Generated by moving electrons.','Power plants, batteries, lightning.'),(4,'Thermal Energy',3,'Energy from temperature differences.','Furnaces, steam systems, geothermal sources.'),(5,'Chemical Energy',4,'Stored in chemical bonds.','Fuels, batteries, food, explosives.'),(8,'Radiant Energy',7,'Energy carried by electromagnetic waves.','Solar energy, light, infrared, ultraviolet, X-rays.'),(9,'Nuclear Energy',8,'Energy stored in atomic nuclei.','Nuclear reactors, stars.'),(10,'Acoustic Energy',9,'Energy carried by sound waves.','Sonar, medical imaging, industrial applications.'),(15,'Bioenergy',14,'Energy derived from organic matter.','Biomass, biogas, biofuels.'),(16,'Tidal Energy',15,'Energy generated from ocean tides.','Tidal power plants.'),(17,'Geothermal Energy',16,'Energy from heat within the Earth.','Hot springs, geothermal power plants.'),(18,'Hydrogen Energy',17,'Energy produced by splitting water molecules.','Fuel cells, hydrogen-powered vehicles.'),(20,'Mechanical Energy',1,'Energy from motion, position, or mechanical forces.','Falling weights, spinning turbines');
/*!40000 ALTER TABLE `energy` ENABLE KEYS */;
