INSERT INTO `energy_stored_category` VALUES (1,'Electrical (Capacitive)',2,'Capacitors, UPS banks, battery strings','Discharge through resistors; meter to ≤ 50 V; insulate & ground'),(2,'Mechanical – Spring/Tension',1,'Springs in presses, valve actuators, counterbalance devices','Relax or pin springs; secure with blocks or straps; verify no rebound'),(3,'Mechanical – Flywheel/Rotational',1,'Grinders, fans, centrifuges','Coast to full stop; apply mechanical brake or blocking bar'),(4,'Gravity (Potential)',1,'Raised loader buckets, suspended loads, overhead dies','Lower to rest on stands/cribbing; use pins/blocks; check stability'),(5,'Hydraulic Pressure',1,'Press cylinders, lift tables, injection molds','De-energise pump; open bleed valves to tank; verify zero gauge pressure'),(6,'Pneumatic Pressure',1,'Air lines, accumulators, pneumatic clamps','Isolate and vent to atmosphere; lock open bleed; gauge reads 0 psi'),(7,'Thermal (Stored Heat)',3,'Steam headers, hot oil circuits, heat exchangers','Isolate, vent/condensate drain; wait to ambient; use IR gun/thermometer'),(8,'Chemical (Reactive/Stored Fuel)',4,'Gas cylinders, fuel tanks, process reagent vessels','Close & cap valves; drain or inert; check for zero flow & safe atmosphere'),(9,'Radiation (Residual Source)',7,'Sealed gamma source in NDT camera, X-ray tube voltage after shutdown','Return source to shielded position; key-lock controller; confirm shutter closed, dose rate ≈ background');
/*!40000 ALTER TABLE `energy_stored_category` ENABLE KEYS */;
