  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `description` text DEFAULT NULL,
  `color` varchar(7) DEFAULT '#3498db' COMMENT 'Hex color for branch visualization',
  `icon` varchar(50) DEFAULT 'fas fa-sitemap' COMMENT 'FontAwesome icon class',
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  `category` varchar(50) DEFAULT NULL COMMENT 'Category: R&D, Manufacturing, Quality, Regulatory, etc.',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `created_by` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_branch_name` (`name`),
  KEY `ix_is_active` (`is_active`),
  KEY `ix_created_by` (`created_by`),
  KEY `ix_category` (`category`),
  CONSTRAINT `process_branches_ibfk_created_by` FOREIGN KEY (`created_by`) REFERENCES `people` (`people_id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=17 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
