INSERT INTO `process_branches` VALUES (2,'MDI Manufacturing','Complete manufacturing flow for Metered Dose Inhaler (MDI) products, including raw materials, API processing, formulation, device components, and filling/assembly processes.','#e74c3c','fas fa-spray-can',1,'Manufacturing','2025-11-24 20:01:05','2025-11-24 21:13:57',NULL),(3,'DPI Manufacturing','Complete manufacturing flow for Dry Powder Inhaler (DPI) products, including raw materials, API processing, powder formulation, device components, and filling/assembly processes.','#27ae60','fas fa-wind',1,'Manufacturing','2025-11-24 20:25:43','2025-11-24 21:13:57',NULL),(4,'Research and Development','Complete R&D process flow for inhalation pharmaceutical products including pre-formulation studies, analytical method development, formulation optimization, device development, stability studies, regulatory documentation, and pre-clinical validation.','#9b59b6','fas fa-flask',1,'R&D','2025-11-24 20:37:09','2025-11-24 21:13:57',NULL),(10,'Regulatory Affairs','Comprehensive regulatory affairs management including submission preparation (IND, NDA, IMPD, MAA), compliance tracking (FDA, EMA, HPRA), document revision history, and product license lifecycle management.','#3498db','fas fa-file-contract',1,'Regulatory','2025-11-24 21:13:57','2025-11-24 21:13:57',NULL),(11,'Quality Assurance & Control','Complete quality management system including batch record review and approval, change control and CAPA management, audit management (internal/external), analytical method validation, OOS handling, deviation investigations, and documentation.','#f39c12','fas fa-shield-alt',1,'Quality','2025-11-24 21:13:57','2025-11-24 21:13:57',NULL),(12,'Packaging & Labeling','End-to-end packaging and labeling operations including packaging material specification and sourcing, label design and regulatory compliance, serialization and anti-counterfeiting documentation, batch packaging workflows, and finished goods release.','#16a085','fas fa-box',1,'Manufacturing','2025-11-24 21:13:57','2025-11-24 21:13:57',NULL),(13,'Supply Chain & Logistics','Complete supply chain management including vendor and material qualification, warehouse operations and stock control, transportation and distribution tracking, cold chain management, and recall management procedures.','#2980b9','fas fa-truck',1,'Supply Chain','2025-11-24 21:13:57','2025-11-24 21:13:57',NULL),(14,'Maintenance & Equipment Management','Comprehensive equipment and maintenance management including preventive and corrective maintenance schedules, equipment calibration records, downtime/uptime tracking, spare parts inventory management, and equipment qualification.','#8e44ad','fas fa-cogs',1,'Operations','2025-11-24 21:13:57','2025-11-24 21:13:57',NULL),(15,'Environmental Health & Safety','Complete EHS management system including risk assessment workflows (HAZOP, 5-Whys, JSA), incident reporting and investigation, waste management tracking, permit-to-work management, and training/competency documentation.','#e67e22','fas fa-hard-hat',1,'EHS','2025-11-24 21:13:57','2025-11-24 21:13:57',NULL),(16,'Clinical Trials Management','End-to-end clinical trial material management including clinical batch manufacturing coordination, clinical site supply and distribution, trial material accountability, patient randomization and blinding workflows, and adverse event/safety reporting.','#c0392b','fas fa-user-md',1,'Clinical','2025-11-24 21:13:57','2025-11-24 21:13:57',NULL);
/*!40000 ALTER TABLE `process_branches` ENABLE KEYS */;
UNLOCK TABLES;

