DROP TABLE IF EXISTS `process_map`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `process_map` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `type` enum('process','step','substep','task','activity') NOT NULL,
  `level` varchar(50) DEFAULT NULL COMMENT 'Process hierarchy level (L0_Enterprise, L1_HighLevel, L2_SubProcess, L3_DetailStep)',
  `status` enum('Active','Inactive','Draft','Archived') NOT NULL DEFAULT 'Active',
  `text` varchar(255) NOT NULL,
  `description` text DEFAULT NULL,
  `cost` decimal(10,2) DEFAULT NULL COMMENT 'Estimated cost in currency units',
  `value_add` tinyint(1) DEFAULT NULL COMMENT '1 = Value-adding, 0 = Non-value-adding, NULL = Not specified',
  `notes` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `created_by` int(11) DEFAULT NULL,
  `updated_by` int(11) DEFAULT NULL,
  `parent` int(11) DEFAULT NULL,
  `owner_id` int(11) DEFAULT NULL,
  `department_id` int(11) DEFAULT NULL,
  `primary_branch_id` int(11) DEFAULT NULL,
  `order` int(11) DEFAULT 0,
  PRIMARY KEY (`id`),
  KEY `parent` (`parent`),
  KEY `ix_status` (`status`),
  KEY `ix_owner_id` (`owner_id`),
  KEY `ix_department_id` (`department_id`),
  KEY `ix_order` (`parent`,`order`),
  KEY `ix_created_by` (`created_by`),
  KEY `ix_updated_by` (`updated_by`),
  KEY `ix_primary_branch_id` (`primary_branch_id`),
  KEY `ix_level` (`level`),
  KEY `ix_value_add` (`value_add`),
  CONSTRAINT `process_map_ibfk_1` FOREIGN KEY (`parent`) REFERENCES `process_map` (`id`),
  CONSTRAINT `process_map_ibfk_created_by` FOREIGN KEY (`created_by`) REFERENCES `people` (`people_id`) ON DELETE SET NULL,
  CONSTRAINT `process_map_ibfk_department` FOREIGN KEY (`department_id`) REFERENCES `departments` (`department_id`) ON DELETE SET NULL,
  CONSTRAINT `process_map_ibfk_owner` FOREIGN KEY (`owner_id`) REFERENCES `people` (`people_id`) ON DELETE SET NULL,
  CONSTRAINT `process_map_ibfk_primary_branch` FOREIGN KEY (`primary_branch_id`) REFERENCES `process_branches` (`id`) ON DELETE SET NULL,
  CONSTRAINT `process_map_ibfk_updated_by` FOREIGN KEY (`updated_by`) REFERENCES `people` (`people_id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=357 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
