LOCK TABLES `process_map` WRITE;
/*!40000 ALTER TABLE `process_map` DISABLE KEYS */;
INSERT INTO `process_map` VALUES (1,'process',NULL,'Active','Research and Development','Comprehensive Research and Development process for inhalation pharmaceutical products covering pre-formulation studies, analytical method development, formulation optimization, device development, stability studies, regulatory documentation, and pre-clinical validation. This process ensures products meet regulatory requirements (FDA, EMA) and are ready for clinical trials. Includes multidisciplinary collaboration between formulation scientists, analytical chemists, device engineers, regulatory affairs, and quality assurance teams.',NULL,NULL,'Critical R&D phase typically takes 18-36 months. All studies must follow GLP/GMP guidelines. Documentation is critical for regulatory submission (IND, IMPD). Requires extensive analytical method development, stability testing, and pre-clinical studies. Device development must meet ISO 20072 standards. Final output: clinical trial-ready product with complete regulatory documentation.','2025-11-23 19:30:11','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,4,0),(2,'step',NULL,'Active','Formulation development','Development of stable, effective formulations for inhalation delivery. Includes API selection, excipient compatibility testing, and stability studies.',NULL,NULL,'Requires collaboration between formulation scientists and analytical chemists. Must meet USP/EP monographs.','2025-11-23 19:30:11','2025-11-24 20:41:28',NULL,NULL,1,NULL,NULL,NULL,1),(3,'substep',NULL,'Active','API selection and characterization','Comprehensive characterization of Active Pharmaceutical Ingredient including particle size, morphology, crystallinity, and purity analysis.',NULL,NULL,'Critical quality attributes: D50 < 5μm for effective lung deposition. Purity must be ≥99.5%.','2025-11-23 19:30:11','2025-11-24 20:41:28',NULL,NULL,2,NULL,NULL,NULL,1),(4,'substep',NULL,'Active','Excipient selection (e.g., lactose for DPIs)','Selection and qualification of excipients (carriers, stabilizers) suitable for inhalation products. Includes compatibility studies and regulatory assessment.',NULL,NULL,'For DPIs: Lactose monohydrate is most common carrier. Must be inhalation grade (Ph.Eur. or USP).','2025-11-23 19:30:11','2025-11-24 20:41:28',NULL,NULL,2,NULL,NULL,NULL,2),(5,'substep',NULL,'Active','Stability testing','Accelerated and long-term stability studies to determine shelf life and storage conditions. Includes ICH Q1A(R2) compliant protocols.',NULL,NULL,'Minimum 6 months real-time data required for initial submission. Must test at 25°C/60% RH and 40°C/75% RH.','2025-11-23 19:30:11','2025-11-24 20:41:28',NULL,NULL,2,NULL,NULL,NULL,3),(6,'step',NULL,'Active','Device design and prototyping','Design and development of inhalation device (MDI actuator, DPI device) including CAD modeling, rapid prototyping, and functional testing.',NULL,NULL,'Device must meet ISO 20072 standards. User testing required for usability assessment.','2025-11-23 19:30:11','2025-11-24 20:41:28',NULL,NULL,1,NULL,NULL,NULL,2),(7,'step',NULL,'Active','Pre-clinical studies','Pre-clinical safety and efficacy studies including in-vitro deposition testing, animal toxicology, and pharmacokinetic studies.',NULL,NULL,'Required for regulatory submission. Must demonstrate safety margin and therapeutic efficacy.','2025-11-23 19:30:11','2025-11-24 20:41:28',NULL,NULL,1,NULL,NULL,NULL,3),(8,'process',NULL,'Active','Raw Material Management','Complete raw material supply chain management including incoming quality control, storage, and inventory management for all inhalation product components.',NULL,NULL,'Critical for both MDI and DPI manufacturing. All materials must be stored under controlled conditions per specifications.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,8,NULL,NULL,2,0),(9,'step',NULL,'Active','Incoming material quality control','Comprehensive quality control testing of incoming raw materials including identity, purity, particle size, and microbiological testing.',NULL,NULL,'All materials must pass COA verification and in-house testing before release to production.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,8,NULL,NULL,NULL,1),(10,'substep',NULL,'Active','Visual inspection','Visual inspection of raw material containers for damage, contamination, and proper labeling. First line of quality control.',NULL,NULL,'Trained inspectors required. Must document any deviations. Reject if container integrity compromised.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,9,NULL,NULL,NULL,1),(11,'substep',NULL,'Active','Quality conformance testing','Laboratory testing to verify raw materials meet specifications including HPLC, GC, particle size analysis, and microbial limits.',NULL,NULL,'Testing must follow validated methods. Results documented in LIMS. Release only after all tests pass.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,9,NULL,NULL,NULL,2),(12,'step',NULL,'Active','Storage of raw materials','Controlled storage of raw materials under specified temperature and humidity conditions. Includes FIFO inventory management.',NULL,NULL,'Temperature monitoring required. API stored in dedicated area with restricted access. Expiry tracking essential.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,8,NULL,NULL,NULL,2),(13,'substep',NULL,'Active','API (Active Pharmaceutical Ingredient)','Dedicated storage area for Active Pharmaceutical Ingredients under controlled conditions. Requires restricted access and environmental monitoring.',NULL,NULL,'Storage: 15-25°C, <60% RH. Requires validated cold chain if applicable. Security measures in place.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,12,NULL,NULL,NULL,1),(14,'substep',NULL,'Active','Excipients','Storage of excipients (lactose, propellants, etc.) in controlled environment. Separate areas for different material types.',NULL,NULL,'Lactose: 15-25°C, <50% RH. Propellants: Follow manufacturer specifications. Segregation from API required.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,12,NULL,NULL,NULL,2),(15,'substep',NULL,'Active','Propellants (for MDIs)','Specialized storage for MDI propellants (HFA-134a, HFA-227) under pressure. Requires explosion-proof facilities.',NULL,NULL,'Critical: Store away from heat sources. Pressure monitoring required. Safety protocols for handling compressed gases.','2025-11-23 19:30:11','2025-11-24 20:25:43',NULL,NULL,12,NULL,NULL,2,3),(16,'substep',NULL,'Active','Packaging materials','Storage of packaging components including canisters, valves, blisters, and labels in clean, dry conditions.',NULL,NULL,'Protect from contamination. First-in-first-out (FIFO) system. Quality checks before use in production.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,12,NULL,NULL,NULL,4),(17,'process',NULL,'Active','API Processing','Processing of Active Pharmaceutical Ingredient to achieve optimal particle size and characteristics for inhalation delivery.',NULL,NULL,'Critical process for both MDI and DPI. Particle size distribution directly impacts lung deposition efficiency.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,17,NULL,NULL,2,1),(18,'step',NULL,'Active','API micronization','Size reduction of API particles to respirable range (<5μm) using jet milling or other micronization techniques.',NULL,NULL,'Target: D50 = 2-3μm, D90 < 5μm. Process must be validated. Monitor for amorphous content formation.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,17,NULL,NULL,NULL,1),(19,'substep',NULL,'Active','Milling to achieve desired particle size','Jet milling process to reduce API particle size. Critical parameters: feed rate, grinding pressure, classifier speed.',NULL,NULL,'Real-time particle size monitoring recommended. Prevent over-milling to avoid amorphous content. GMP environment required.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,18,NULL,NULL,NULL,1),(20,'substep',NULL,'Active','Particle size distribution analysis','Characterization of particle size distribution using laser diffraction (Malvern Mastersizer) or cascade impaction.',NULL,NULL,'Method validation required. Report D10, D50, D90, and span. Compare against target specifications.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,18,NULL,NULL,NULL,2),(21,'step',NULL,'Active','Crystallinity and surface morphology testing','Analysis of crystalline form and surface morphology using XRPD, DSC, and SEM to ensure stability and performance.',NULL,NULL,'Polymorphic form must be stable. Monitor for form conversion during processing. Document crystal habit.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,17,NULL,NULL,NULL,2),(22,'process',NULL,'Active','Formulation Preparation','Preparation of drug formulations for both MDI and DPI products. Includes blending, homogenization, and quality control.',NULL,NULL,'Separate processes for MDI (suspension/solution) and DPI (powder blend). Both require validated mixing procedures.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,18,NULL,NULL,2,2),(23,'step',NULL,'Active','For DPIs','Formulation preparation specific to Dry Powder Inhalers: blending micronized API with carrier particles (lactose).',NULL,NULL,'Critical: Achieve uniform distribution without over-blending. Typical blend ratio: 1-5% API, 95-99% carrier.','2025-11-23 19:30:11','2025-11-24 20:25:43',NULL,NULL,22,NULL,NULL,3,1),(24,'substep',NULL,'Active','Blending of micronized API with carrier (e.g., lactose)','Turbula or V-blender mixing of micronized API with inhalation-grade lactose carrier. Optimize blend time for uniformity.',NULL,NULL,'Blend uniformity testing required (RSD <5%). Prevent segregation. Typical blend time: 15-30 minutes.','2025-11-23 19:30:11','2025-11-24 20:25:43',NULL,NULL,23,NULL,NULL,3,1),(25,'substep',NULL,'Active','Homogenization','Additional mixing step to ensure uniform distribution of API particles on carrier surface. May use high-shear mixing.',NULL,NULL,'Balance between uniformity and particle detachment. Over-mixing can reduce fine particle fraction.','2025-11-23 19:30:11','2025-11-24 20:25:43',NULL,NULL,23,NULL,NULL,3,2),(26,'step',NULL,'Active','For MDIs','Formulation preparation for Metered Dose Inhalers: preparation of drug suspension or solution in propellant system.',NULL,NULL,'Suspension: drug particles in propellant. Solution: drug dissolved in propellant/co-solvent. Different stability profiles.','2025-11-23 19:30:11','2025-11-24 20:25:43',NULL,NULL,22,NULL,NULL,2,2),(27,'substep',NULL,'Active','Preparation of drug suspension/solution','Preparation of drug suspension (particles in propellant) or solution (dissolved drug) with appropriate stabilizers and co-solvents.',NULL,NULL,'Suspension: requires surfactant to prevent agglomeration. Solution: may require co-solvent (ethanol). Both need stability testing.','2025-11-23 19:30:11','2025-11-24 20:25:43',NULL,NULL,26,NULL,NULL,2,1),(28,'substep',NULL,'Active','Mixing with propellant','Mixing of drug formulation with HFA propellant under controlled conditions. Requires pressure vessel and temperature control.',NULL,NULL,'Critical: Maintain temperature to prevent propellant evaporation. Homogeneous mixing essential. Pressure: 3-5 bar typical.','2025-11-23 19:30:11','2025-11-24 20:25:43',NULL,NULL,26,NULL,NULL,2,2),(29,'process',NULL,'Active','Device Components Manufacturing','Manufacturing of device components including plastic parts, metal canisters, valves, and actuators for inhalation products.',NULL,NULL,'Components must meet ISO standards and regulatory requirements. Quality control at each manufacturing step.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,22,NULL,NULL,2,3),(30,'step',NULL,'Active','Injection molding of plastic components','Injection molding of plastic components (actuators, mouthpieces, device bodies) using medical-grade polymers.',NULL,NULL,'Materials: PP, PE, or medical-grade plastics. Must meet USP Class VI. Cleanroom manufacturing required.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,29,NULL,NULL,NULL,1),(31,'step',NULL,'Active','Metal components fabrication (e.g., canisters for MDIs)','Manufacturing of aluminum canisters for MDIs including deep drawing, anodizing, and quality inspection.',NULL,NULL,'Canister must be leak-tight, compatible with propellant, and meet dimensional specifications. Coating may be required.','2025-11-23 19:30:11','2025-11-24 20:25:43',NULL,NULL,29,NULL,NULL,2,2),(32,'step',NULL,'Active','Assembly of device parts','Assembly of device components including valve mounting, actuator attachment, and functional testing.',NULL,NULL,'Assembly in cleanroom environment. Functional testing: spray pattern, dose uniformity, leak testing.','2025-11-23 19:30:11','2025-11-24 20:25:42',NULL,NULL,29,NULL,NULL,NULL,3),(33,'process',NULL,'Active','Filling and Assembly','Final filling of drug product into devices and assembly. Includes dose uniformity testing and packaging.',NULL,NULL,'Critical process requiring validated filling equipment. Separate procedures for MDI and DPI products.','2025-11-23 19:30:11','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,2,4),(34,'step',NULL,'Active','For DPIs','Filling of powder formulation into DPI device reservoirs or blisters. Requires precision dosing equipment.',NULL,NULL,'Dose weight: typically 5-25mg per dose. Weight variation: ±10% acceptable. In-process controls required.','2025-11-23 19:30:11','2025-11-24 20:25:43',NULL,NULL,33,NULL,NULL,3,1),(35,'substep',NULL,'Active','Powder filling into blisters or reservoirs','Automated filling of powder blend into device reservoirs or unit-dose blisters using auger or dosator systems.',NULL,NULL,'Critical: Maintain blend uniformity during filling. Prevent segregation. Environmental controls: <30% RH.','2025-11-23 19:30:11','2025-11-24 20:25:43',NULL,NULL,34,NULL,NULL,3,1),(36,'substep',NULL,'Active','Device assembly','Final assembly of DPI device including reservoir/blister loading, mechanism assembly, and packaging.',NULL,NULL,'Assembly in controlled environment. Functional testing: dose delivery, airflow resistance. Leak testing if applicable.','2025-11-23 19:30:11','2025-11-24 20:25:43',NULL,NULL,34,NULL,NULL,3,2),(37,'step',NULL,'Active','For MDIs','Filling of MDI canisters with drug-propellant formulation under pressure. Includes valve crimping and actuator attachment.',NULL,NULL,'Cold-fill or pressure-fill method. Dose volume: typically 50-100μL. Requires validated filling equipment.','2025-11-23 19:30:11','2025-11-24 20:25:43',NULL,NULL,33,NULL,1,2,2),(38,'substep',NULL,'Active','Canister filling with drug formulation and propellant','Filling of drug-propellant formulation into aluminum canisters under controlled pressure and temperature conditions.',NULL,NULL,'Fill weight: typically 10-20g per canister. Pressure: 3-5 bar. Temperature control critical. Leak testing required.','2025-11-23 19:30:11','2025-11-24 20:25:43',NULL,NULL,37,NULL,2,2,1),(39,'substep',NULL,'Active','Valve crimping','Crimping of metering valve onto filled canister using specialized crimping equipment. Ensures leak-tight seal.',NULL,NULL,'Crimp height and force must be within specifications. 100% leak testing required. Visual inspection for defects.','2025-11-23 19:30:11','2025-11-24 20:25:43',NULL,NULL,37,NULL,6,2,2),(40,'substep',NULL,'Active','Actuator attachment','Attachment of actuator/mouthpiece to crimped canister. Includes functional testing and priming.',NULL,NULL,'Snap-fit or threaded attachment. Prime device (waste 2-3 shots) before use. Dose uniformity testing on filled units.','2025-11-23 19:30:11','2025-11-24 20:25:43',NULL,NULL,37,NULL,5,2,3),(100,'substep',NULL,'Active','Pre-formulation compatibility studies','Evaluation of API-excipient compatibility using binary mixtures, thermal analysis (DSC, TGA), and accelerated stress testing to identify potential interactions.',NULL,NULL,'Critical step to prevent formulation failures. Test at 40°C/75% RH for 1-3 months. Monitor for color changes, degradation, polymorphic transitions.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,2,NULL,NULL,NULL,4),(101,'task',NULL,'Active','Prepare binary mixtures','Prepare 1:1 w/w binary mixtures of API with each excipient candidate for compatibility testing.',NULL,NULL,'Use analytical balance. Document exact ratios. Store in controlled conditions.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,100,NULL,NULL,NULL,1),(102,'task',NULL,'Active','Perform DSC analysis','Differential Scanning Calorimetry analysis to detect physical interactions and polymorphic changes.',NULL,NULL,'Heating rate: 10°C/min. Temperature range: 25-300°C. Compare with individual components.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,100,NULL,NULL,NULL,2),(103,'task',NULL,'Active','Conduct accelerated stress testing','Store binary mixtures at 40°C/75% RH for 1-3 months and analyze for degradation products.',NULL,NULL,'Sample at 0, 1, 2, 3 months. Use HPLC for degradation product analysis.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,100,NULL,NULL,NULL,3),(104,'activity',NULL,'Active','Document compatibility results','Compile compatibility study report with recommendations for excipient selection.',NULL,NULL,'Include all analytical data, photographs, and conclusions. Review with formulation team.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,100,NULL,NULL,NULL,4),(105,'substep',NULL,'Active','Formulation optimization using DoE','Design of Experiments approach to optimize formulation parameters (API concentration, excipient ratio, mixing conditions) to achieve target performance.',NULL,NULL,'Use statistical software (JMP, Design-Expert). Typical factors: API%, carrier type, blend time. Responses: FPF, dose uniformity, stability.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,2,NULL,NULL,NULL,5),(106,'task',NULL,'Active','Design experimental matrix','Create factorial or response surface design to systematically vary formulation parameters.',NULL,NULL,'Include center points for curvature detection. Randomize run order. Plan 15-30 experiments.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,105,NULL,NULL,NULL,1),(107,'task',NULL,'Active','Prepare experimental batches','Manufacture formulation batches according to DoE matrix with precise control of variables.',NULL,NULL,'Document all process parameters. Use calibrated equipment. Maintain batch records.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,105,NULL,NULL,NULL,2),(108,'task',NULL,'Active','Characterize formulations','Test all batches for key performance indicators: fine particle fraction (FPF), dose uniformity, flow properties.',NULL,NULL,'Use cascade impaction for FPF. USP <601> for dose uniformity. Flow properties: angle of repose, Carr index.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,105,NULL,NULL,NULL,3),(109,'activity',NULL,'Active','Statistical analysis and optimization','Analyze results using regression analysis to identify optimal formulation parameters.',NULL,NULL,'Generate response surface plots. Identify design space. Validate optimal formulation with confirmation runs.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,105,NULL,NULL,NULL,4),(110,'substep',NULL,'Active','Analytical method development and validation','Development and validation of analytical methods for API assay, degradation products, particle size, and dose content uniformity per ICH Q2(R1).',NULL,NULL,'Methods must be specific, accurate, precise, linear, and robust. Validation required before use in stability studies.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,2,NULL,NULL,NULL,6),(111,'task',NULL,'Active','Develop HPLC method for assay','Develop and optimize HPLC method for API quantification in formulation with appropriate specificity and sensitivity.',NULL,NULL,'Method development: column selection, mobile phase optimization, detection wavelength. Target: LOD < 0.1%, LOQ < 0.3%.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,110,NULL,NULL,NULL,1),(112,'task',NULL,'Active','Develop method for degradation products','Develop HPLC method with gradient elution to separate and quantify degradation products (impurities).',NULL,NULL,'Must separate all known and potential degradation products. Use forced degradation studies to identify peaks.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,110,NULL,NULL,NULL,2),(113,'task',NULL,'Active','Validate particle size method','Validate laser diffraction method (Malvern Mastersizer) for particle size distribution analysis.',NULL,NULL,'Validation: precision (RSD < 5%), accuracy (recovery 95-105%), robustness. Include sample preparation procedure.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,110,NULL,NULL,NULL,3),(114,'activity',NULL,'Active','Complete method validation report','Document all validation data per ICH Q2(R1) including system suitability, specificity, linearity, accuracy, precision, LOD/LOQ, robustness.',NULL,NULL,'Review with QA. Include in regulatory submission. Method must be transferable to QC laboratory.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,110,NULL,NULL,NULL,4),(115,'substep',NULL,'Active','Concept design and requirements definition','Define device requirements including dose delivery mechanism, airflow resistance, user interface, and ergonomic considerations.',NULL,NULL,'Requirements: dose accuracy ±15%, airflow resistance 0.01-0.05 kPa·s/L, user-friendly operation. Document in Design Requirements Specification.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,6,NULL,NULL,NULL,1),(116,'substep',NULL,'Active','CAD modeling and engineering design','3D CAD modeling of device components including detailed engineering drawings, tolerances, and material specifications.',NULL,NULL,'Use SolidWorks, CATIA, or similar. Include all dimensions, tolerances, surface finishes. Design for manufacturability (DFM).','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,6,NULL,NULL,NULL,2),(117,'substep',NULL,'Active','Rapid prototyping and iterative design','3D printing and rapid prototyping of device concepts for functional testing and design iteration.',NULL,NULL,'Materials: SLA, SLS, or FDM. Multiple iterations typical. Test form, fit, and function. Refine design based on feedback.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,6,NULL,NULL,NULL,3),(118,'substep',NULL,'Active','Functional testing and performance validation','Testing of prototype devices for dose delivery, airflow characteristics, spray pattern (MDI), and powder dispersion (DPI).',NULL,NULL,'Test methods: cascade impaction, laser diffraction, high-speed video. Compare against target specifications. Document all results.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,6,NULL,NULL,NULL,4),(119,'substep',NULL,'Active','User studies and usability testing','Human factors studies with target patient population to assess device usability, ease of use, and patient preference.',NULL,NULL,'Follow FDA Human Factors Guidance. Test with 20-30 participants. Assess: ease of use, error rates, patient satisfaction. Document findings.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,6,NULL,NULL,NULL,5),(120,'task',NULL,'Active','Create actuator body model','3D CAD model of MDI actuator body with internal channels, valve interface, and mouthpiece connection.',NULL,NULL,'Critical dimensions: valve stem diameter, spray channel geometry. Material: medical-grade PP or PE.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,116,NULL,NULL,NULL,1),(121,'task',NULL,'Active','Design DPI device mechanism','CAD model of DPI device including powder reservoir, dose metering mechanism, and airflow channels.',NULL,NULL,'Mechanism must provide consistent dose delivery. Airflow resistance critical for patient inhalation effort.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,116,NULL,NULL,NULL,2),(122,'activity',NULL,'Active','Generate engineering drawings','Create detailed 2D engineering drawings from 3D models with all dimensions, tolerances, and GD&T symbols.',NULL,NULL,'Follow ASME Y14.5 standards. Include: front view, side view, section views, detail views. Review with manufacturing team.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,116,NULL,NULL,NULL,3),(123,'task',NULL,'Active','3D print prototype components','Print device components using appropriate 3D printing technology (SLA, SLS, FDM) based on requirements.',NULL,NULL,'SLA: high detail, smooth finish. SLS: functional parts, good mechanical properties. Post-process: sanding, support removal.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,117,NULL,NULL,NULL,1),(124,'task',NULL,'Active','Assemble prototype devices','Assemble 3D printed components into functional prototype devices for testing.',NULL,NULL,'May require additional components (valves, springs). Document assembly procedure. Test fit and function.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,117,NULL,NULL,NULL,2),(125,'activity',NULL,'Active','Functional testing of prototypes','Test prototype devices for dose delivery, airflow, and mechanical function. Compare against design targets.',NULL,NULL,'Test: dose uniformity, spray pattern (MDI), powder dispersion (DPI), airflow resistance. Document all results. Iterate if needed.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,117,NULL,NULL,NULL,3),(126,'substep',NULL,'Active','In-vitro deposition testing','Cascade impaction studies (Andersen, Next Generation Impactor) to characterize aerosol performance and lung deposition profile.',NULL,NULL,'Test conditions: flow rate 28.3 L/min (MDI) or 60 L/min (DPI). Calculate: FPF, MMAD, GSD. Compare against target profile.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,7,NULL,NULL,NULL,1),(127,'substep',NULL,'Active','Animal toxicology studies','Repeat-dose toxicology studies in rodents and non-rodents to assess safety and establish NOAEL (No Observed Adverse Effect Level).',NULL,NULL,'Follow ICH M3(R2). Typical: 28-day and 90-day studies. Monitor: clinical signs, body weight, food consumption, clinical pathology, histopathology.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,7,NULL,NULL,NULL,2),(128,'substep',NULL,'Active','Pharmacokinetic studies','PK studies in animals to understand absorption, distribution, metabolism, and excretion (ADME) of the drug after inhalation.',NULL,NULL,'Study: plasma concentration-time profiles, bioavailability, half-life, clearance. Compare IV vs. inhalation routes.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,7,NULL,NULL,NULL,3),(129,'substep',NULL,'Active','Safety pharmacology studies','Assessment of effects on vital organ systems (cardiovascular, respiratory, central nervous system) at therapeutic and supra-therapeutic doses.',NULL,NULL,'Follow ICH S7A. Test: cardiovascular (ECG, blood pressure), respiratory (respiratory rate, tidal volume), CNS (behavioral observations).','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,7,NULL,NULL,NULL,4),(130,'substep',NULL,'Active','Genotoxicity studies','Assessment of potential genotoxic effects using bacterial reverse mutation assay (Ames test) and in-vitro mammalian cell tests.',NULL,NULL,'Follow ICH S2(R1). Required before first-in-human studies. Must be negative for clinical progression.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,7,NULL,NULL,NULL,5),(131,'task',NULL,'Active','Set up cascade impactor','Calibrate and prepare cascade impactor (Andersen or NGI) according to pharmacopoeial methods (USP <601>).',NULL,NULL,'Calibrate flow rate. Pre-condition impactor plates with coating solution. Document environmental conditions (T, RH).','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,126,NULL,NULL,NULL,1),(132,'task',NULL,'Active','Perform actuation and collection','Actuate device into impactor at specified flow rate. Collect drug on each stage and filter.',NULL,NULL,'MDI: actuate at t=0. DPI: use vacuum pump at 60 L/min. Collect for specified number of actuations (typically 10).','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,126,NULL,NULL,NULL,2),(133,'task',NULL,'Active','Analyze stage deposits','Extract drug from each impactor stage and analyze using validated HPLC method to quantify drug mass per stage.',NULL,NULL,'Extract with appropriate solvent. Analyze by HPLC. Calculate mass per stage. Sum to get total recovered dose.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,126,NULL,NULL,NULL,3),(134,'activity',NULL,'Active','Calculate deposition parameters','Calculate fine particle fraction (FPF), mass median aerodynamic diameter (MMAD), and geometric standard deviation (GSD).',NULL,NULL,'FPF = mass < 5μm / total recovered. MMAD from cumulative distribution. GSD from log-normal fit. Compare against targets.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,126,NULL,NULL,NULL,4),(135,'step',NULL,'Active','Regulatory documentation and submission preparation','Preparation of comprehensive regulatory documentation including IND (Investigational New Drug), IMPD (Investigational Medicinal Product Dossier), and supporting documents for FDA/EMA submission.',NULL,NULL,'Critical for clinical trial authorization. Requires multidisciplinary input. Follow CTD format. Timeline: 3-6 months preparation.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,1,NULL,NULL,NULL,4),(136,'substep',NULL,'Active','Module 2: Quality Overall Summary','Preparation of Quality Overall Summary (QOS) including drug substance, drug product, and analytical methods summaries.',NULL,NULL,'Follow ICH M4Q(R1). Include: manufacturing process, specifications, analytical methods, stability data. Review with regulatory affairs.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,135,NULL,NULL,NULL,1),(137,'substep',NULL,'Active','Module 3: Quality Documentation','Complete Module 3 documentation including drug substance and drug product information, manufacturing process, specifications, and analytical methods.',NULL,NULL,'Detailed documentation of all quality aspects. Include: batch records, validation reports, stability protocols and reports, analytical method validation.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,135,NULL,NULL,NULL,2),(138,'substep',NULL,'Active','Module 4: Non-clinical Study Reports','Compilation of all non-clinical study reports including toxicology, pharmacokinetics, and safety pharmacology studies.',NULL,NULL,'Include: study protocols, final reports, GLP compliance statements. All studies must be conducted per GLP guidelines.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,135,NULL,NULL,NULL,3),(139,'substep',NULL,'Active','Clinical trial application submission','Submission of IND (FDA) or IMPD/CTA (EMA) application to regulatory authorities for authorization to conduct clinical trials.',NULL,NULL,'Coordinate with regulatory affairs. Submit electronically (eCTD format preferred). Prepare for potential questions from regulatory reviewers.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,135,NULL,NULL,NULL,4),(140,'task',NULL,'Active','Prepare drug substance summary','Summary of drug substance (API) including manufacturing process, characterization, specifications, and stability.',NULL,NULL,'Include: synthetic route, impurities, particle size, polymorphic form, stability data. Keep concise but complete.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,136,NULL,NULL,NULL,1),(141,'task',NULL,'Active','Prepare drug product summary','Summary of drug product including formulation, manufacturing process, specifications, and stability data.',NULL,NULL,'Include: composition, manufacturing steps, critical process parameters, specifications, stability protocol and results.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,136,NULL,NULL,NULL,2),(142,'activity',NULL,'Active','Review and finalize QOS','Internal review of Quality Overall Summary with quality, regulatory, and technical teams. Finalize for submission.',NULL,NULL,'Ensure consistency with Module 3. Address all reviewer comments. Obtain management approval before submission.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,136,NULL,NULL,NULL,3),(143,'step',NULL,'Active','Clinical trial material preparation','Preparation of clinical trial materials including manufacturing, packaging, labeling, and release testing of investigational product for Phase I/II studies.',NULL,NULL,'Must be manufactured under GMP conditions. Requires qualified manufacturing facility. Timeline: 2-3 months for first clinical batch.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,1,NULL,NULL,NULL,5),(144,'substep',NULL,'Active','Clinical batch manufacturing','Manufacture of clinical trial material batches under GMP conditions following validated manufacturing process.',NULL,NULL,'Batch size: typically 1000-5000 units. Document all process parameters. In-process controls required. Batch record must be complete.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,143,NULL,NULL,NULL,1),(145,'substep',NULL,'Active','Packaging and labeling','Packaging of clinical trial materials with appropriate labeling including randomization codes, expiry dates, and storage conditions.',NULL,NULL,'Follow GMP packaging requirements. Labeling must comply with regulatory requirements. Include: batch number, expiry, storage conditions, \"For clinical trial use only\".','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,143,NULL,NULL,NULL,2),(146,'substep',NULL,'Active','Release testing and quality control','Complete quality control testing and release of clinical trial materials including assay, impurities, dose uniformity, and microbial testing.',NULL,NULL,'All tests must pass specifications. Release by Qualified Person (EU) or authorized person (US). Document in Certificate of Analysis.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,143,NULL,NULL,NULL,3),(147,'substep',NULL,'Active','Stability testing of clinical materials','Ongoing stability testing of clinical trial materials to support expiry dating and storage conditions.',NULL,NULL,'Test at specified intervals (0, 1, 3, 6, 12 months). Monitor: appearance, assay, impurities, particle size. Update stability report as data becomes available.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,143,NULL,NULL,NULL,4),(148,'task',NULL,'Active','Prepare manufacturing batch record','Prepare detailed batch record for clinical trial material manufacturing including all process steps, parameters, and acceptance criteria.',NULL,NULL,'Include: material quantities, equipment settings, process parameters, in-process controls, sampling plan. Review and approve before use.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,144,NULL,NULL,NULL,1),(149,'task',NULL,'Active','Manufacture clinical batch','Execute manufacturing of clinical trial batch following approved batch record under GMP conditions.',NULL,NULL,'Document all deviations. Perform in-process controls. Collect samples for testing. Maintain cleanroom environment.','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,144,NULL,NULL,NULL,2),(150,'activity',NULL,'Active','Complete batch documentation','Complete all batch documentation including batch record, deviation reports (if any), and prepare for quality review.',NULL,NULL,'Ensure all entries are complete, legible, and signed. Attach all supporting documentation (COAs, calibration certificates).','2025-11-24 20:40:41','2025-11-24 20:40:41',NULL,NULL,144,NULL,NULL,NULL,3),(151,'process',NULL,'Active','Regulatory Submission Preparation','Comprehensive process for preparing regulatory submissions including IND (Investigational New Drug), NDA (New Drug Application), IMPD (Investigational Medicinal Product Dossier), and MAA (Marketing Authorization Application) for FDA, EMA, HPRA, and other regulatory authorities.',NULL,NULL,'Critical process requiring multidisciplinary coordination. Follows CTD (Common Technical Document) format. Timeline: 3-6 months for initial submission preparation. All documents must be eCTD compliant.','2025-11-24 21:06:54','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(152,'step',NULL,'Active','IND/IMPD Preparation','Preparation of Investigational New Drug (FDA) or Investigational Medicinal Product Dossier (EMA) application for authorization to conduct clinical trials.',NULL,NULL,'Includes: Module 1 (Administrative), Module 2 (Summaries), Module 3 (Quality), Module 4 (Non-clinical), Module 5 (Clinical protocol). Requires cross-functional team input.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,151,NULL,NULL,NULL,1),(153,'step',NULL,'Active','NDA/MAA Preparation','Preparation of New Drug Application (FDA) or Marketing Authorization Application (EMA) for product approval and market authorization.',NULL,NULL,'Comprehensive submission including all clinical data, manufacturing information, labeling, and risk management plans. Requires extensive documentation and data analysis.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,151,NULL,NULL,NULL,2),(154,'step',NULL,'Active','Post-Marketing Submissions','Management of post-approval submissions including variations, supplements, annual reports, and safety updates.',NULL,NULL,'Ongoing regulatory maintenance. Includes: Type IA/IB variations (EU), CBE-30/CBE-0 supplements (US), PADER (Periodic Adverse Drug Experience Reports), PSUR (Periodic Safety Update Reports).','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,151,NULL,NULL,NULL,3),(155,'substep',NULL,'Active','Module 1: Administrative Information','Compilation of administrative documents including application forms, cover letters, table of contents, and regional information.',NULL,NULL,'FDA Form 1571/1572 (IND), EU Application Form. Include: applicant information, product information, proposed indication, orphan drug designation (if applicable).','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,152,NULL,NULL,NULL,1),(156,'substep',NULL,'Active','Module 2: Quality Overall Summary','Preparation of Quality Overall Summary (QOS) summarizing drug substance, drug product, and analytical methods.',NULL,NULL,'Follow ICH M4Q(R1). Include: manufacturing process summary, specifications, analytical methods summary, stability data summary. Keep concise but complete.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,152,NULL,NULL,NULL,2),(157,'substep',NULL,'Active','Module 3: Quality Documentation','Complete quality documentation including drug substance and drug product information, manufacturing process, specifications, and analytical methods.',NULL,NULL,'Detailed documentation: batch records, validation reports, stability protocols and reports, analytical method validation, container closure system.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,152,NULL,NULL,NULL,3),(158,'substep',NULL,'Active','Module 4: Non-clinical Study Reports','Compilation of all non-clinical study reports including toxicology, pharmacokinetics, and safety pharmacology.',NULL,NULL,'Include: study protocols, final reports, GLP compliance statements. All studies must be conducted per GLP guidelines. Cross-reference to Module 2 summaries.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,152,NULL,NULL,NULL,4),(159,'substep',NULL,'Active','Module 5: Clinical Protocol and Information','Clinical trial protocol, investigator brochure, and clinical trial authorization documentation.',NULL,NULL,'Protocol must be scientifically sound and ethically acceptable. Include: study design, inclusion/exclusion criteria, endpoints, statistical analysis plan, informed consent form.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,152,NULL,NULL,NULL,5),(160,'substep',NULL,'Active','eCTD Compilation and Submission','Compilation of submission in eCTD (electronic Common Technical Document) format and submission to regulatory authorities.',NULL,NULL,'Use validated eCTD software. Ensure proper XML structure, hyperlinking, and document organization. Submit electronically via FDA ESG or EMA Gateway.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,152,NULL,NULL,NULL,6),(161,'task',NULL,'Active','Complete application forms','Fill out regulatory application forms (FDA Form 1571/1572 for IND, EU Application Form for IMPD) with all required information.',NULL,NULL,'Ensure all fields completed accurately. Signatures required from sponsor and investigators. Review for completeness before submission.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,155,NULL,NULL,NULL,1),(162,'task',NULL,'Active','Prepare cover letter','Draft cover letter to regulatory authority introducing the submission and highlighting key points.',NULL,NULL,'Include: submission type, product name, indication, request for authorization, contact information. Professional tone, clear and concise.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,155,NULL,NULL,NULL,2),(163,'activity',NULL,'Active','Compile administrative documents','Gather and organize all administrative documents including certificates, authorizations, and declarations.',NULL,NULL,'Check completeness: GMP certificates, manufacturing authorizations, import licenses (if applicable), orphan drug designation (if applicable).','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,155,NULL,NULL,NULL,3),(164,'process',NULL,'Active','Regulatory Compliance Tracking','Systematic tracking of regulatory compliance across multiple jurisdictions (FDA, EMA, HPRA, Health Canada, TGA, etc.) including submission status, approval timelines, and regulatory commitments.',NULL,NULL,'Critical for maintaining market authorization. Track: submission dates, review timelines, information requests, approval dates, post-marketing commitments, inspection schedules.','2025-11-24 21:06:54','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(165,'step',NULL,'Active','FDA Compliance Tracking','Tracking of FDA submissions, approvals, and post-marketing requirements including PDUFA dates, user fee payments, and inspection schedules.',NULL,NULL,'Monitor: IND status, NDA review timeline, PDUFA goal dates, information requests, advisory committee meetings, approval letters, post-marketing commitments.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,164,NULL,NULL,NULL,1),(166,'step',NULL,'Active','EMA/HPRA Compliance Tracking','Tracking of European regulatory submissions including IMPD, MAA, variations, and post-authorization commitments.',NULL,NULL,'Monitor: validation dates, assessment timelines, Day 120/180 questions, CHMP opinion, authorization dates, post-authorization measures, PSUR submission dates.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,164,NULL,NULL,NULL,2),(167,'step',NULL,'Active','Multi-Jurisdictional Coordination','Coordination of regulatory activities across multiple jurisdictions to ensure consistent submissions and timely approvals.',NULL,NULL,'Synchronize submission timelines where possible. Coordinate responses to similar questions. Maintain master regulatory timeline. Track country-specific requirements.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,164,NULL,NULL,NULL,3),(168,'process',NULL,'Active','Document Revision History Management','Comprehensive document control system for tracking revision history of regulatory documents including protocols, reports, specifications, and SOPs.',NULL,NULL,'Maintains audit trail of all document changes. Includes: version control, change justification, approval workflow, effective dates, superseded documents archive.','2025-11-24 21:06:54','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(169,'step',NULL,'Active','Document Change Control','Formal process for requesting, reviewing, approving, and implementing document changes.',NULL,NULL,'Change request → Impact assessment → Review → Approval → Implementation → Training. Document all changes with justification.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,168,NULL,NULL,NULL,1),(170,'step',NULL,'Active','Version Control and Archive','Maintenance of document versions and archive of superseded documents for regulatory inspection readiness.',NULL,NULL,'All versions retained. Archive system searchable. Retention per regulatory requirements (typically 10+ years). Easy retrieval for inspections.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,168,NULL,NULL,NULL,2),(171,'process',NULL,'Active','Product License Lifecycle Management','End-to-end management of product license lifecycle from initial application through renewal, variations, and eventual withdrawal.',NULL,NULL,'Tracks: application submission → approval → post-marketing variations → renewals → license maintenance → withdrawal (if applicable).','2025-11-24 21:06:54','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(172,'step',NULL,'Active','License Application and Approval','Initial product license application and approval process including preparation, submission, review, and authorization.',NULL,NULL,'Timeline: 6-12 months typical. Monitor review progress. Respond to questions promptly. Prepare for potential advisory committee.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,171,NULL,NULL,NULL,1),(173,'step',NULL,'Active','Post-Marketing Variations','Management of post-approval changes including manufacturing changes, labeling updates, and indication expansions.',NULL,NULL,'Classify variations: Type IA/IB/II (EU), CBE-30/CBE-0/PAS (US). Assess regulatory impact. Submit appropriate variation application.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,171,NULL,NULL,NULL,2),(174,'step',NULL,'Active','License Renewal','Periodic license renewal process to maintain market authorization.',NULL,NULL,'EU: Renewal every 5 years. US: Annual reports. Prepare renewal documentation including safety and efficacy updates, post-marketing commitments status.','2025-11-24 21:06:54','2025-11-24 21:06:54',NULL,NULL,171,NULL,NULL,NULL,3),(175,'process',NULL,'Active','Batch Record Review and Approval','Comprehensive batch record review process including manufacturing batch records, packaging records, and quality control test results to ensure compliance with specifications before product release.',NULL,NULL,'Critical quality gate. All batch records must be reviewed and approved by authorized personnel (Qualified Person in EU, authorized person in US) before release. Review includes: completeness, accuracy, deviations, test results, environmental monitoring.','2025-11-24 21:07:13','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(176,'step',NULL,'Active','Manufacturing Batch Record Review','Review of manufacturing batch records for completeness, accuracy, and compliance with approved procedures.',NULL,NULL,'Check: material quantities, process parameters, in-process controls, sampling, environmental conditions, equipment used, operator signatures, timestamps. Document any discrepancies.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,175,NULL,NULL,NULL,1),(177,'step',NULL,'Active','Quality Control Test Results Review','Review of all QC test results including assay, impurities, dose uniformity, particle size, microbial limits, and container closure integrity.',NULL,NULL,'Verify: all tests performed, results within specifications, methods validated, equipment calibrated, analysts qualified. Investigate any OOS results.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,175,NULL,NULL,NULL,2),(178,'step',NULL,'Active','Deviation and Investigation Review','Review of any deviations, non-conformances, or investigations associated with the batch.',NULL,NULL,'Assess: impact on product quality, root cause analysis completeness, corrective actions taken, preventive measures. Ensure deviations properly documented and closed.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,175,NULL,NULL,NULL,3),(179,'step',NULL,'Active','Final Release Decision','Final review and release decision by Qualified Person (EU) or authorized person (US) based on complete batch documentation.',NULL,NULL,'Decision criteria: all tests passed, no critical deviations, documentation complete, batch meets specifications. Document release decision with signature and date.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,175,NULL,NULL,NULL,4),(180,'substep',NULL,'Active','Completeness Check','Verify all required sections of batch record are completed including material reconciliation, process steps, and signatures.',NULL,NULL,'Checklist: material quantities, process parameters documented, all steps signed, timestamps present, no blank fields. Flag incomplete records for correction.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,176,NULL,NULL,NULL,1),(181,'substep',NULL,'Active','Accuracy Verification','Verify accuracy of recorded data including calculations, measurements, and process parameters against approved ranges.',NULL,NULL,'Compare: material weights against BOM, process parameters against validated ranges, calculations verified. Document any discrepancies.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,176,NULL,NULL,NULL,2),(182,'substep',NULL,'Active','Compliance Assessment','Assess compliance with approved procedures, specifications, and regulatory requirements.',NULL,NULL,'Verify: procedures followed, specifications met, environmental conditions within limits, equipment qualified, operators trained. Document compliance status.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,176,NULL,NULL,NULL,3),(183,'process',NULL,'Active','Change Control and CAPA Management','Formal change control process for managing changes to processes, procedures, equipment, and systems, plus Corrective and Preventive Action (CAPA) system for addressing non-conformances.',NULL,NULL,'All changes must be assessed for impact on product quality, safety, and efficacy. CAPA system ensures systematic approach to problem resolution and prevention.','2025-11-24 21:07:13','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(184,'step',NULL,'Active','Change Request and Impact Assessment','Formal change request process including description of proposed change, justification, and comprehensive impact assessment.',NULL,NULL,'Assess impact on: product quality, regulatory compliance, validation status, documentation, training needs, supply chain. Classify change: minor, major, critical.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,183,NULL,NULL,NULL,1),(185,'step',NULL,'Active','Change Review and Approval','Multi-disciplinary review and approval of change requests by appropriate stakeholders including QA, Regulatory, Manufacturing, and Engineering.',NULL,NULL,'Review team evaluates: technical feasibility, quality impact, regulatory implications, resource requirements, timeline. Approval required before implementation.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,183,NULL,NULL,NULL,2),(186,'step',NULL,'Active','Change Implementation and Verification','Implementation of approved changes including validation (if required), documentation updates, training, and verification of effectiveness.',NULL,NULL,'Implement per approved plan. Update procedures, batch records, specifications as needed. Train affected personnel. Verify change implemented correctly.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,183,NULL,NULL,NULL,3),(187,'step',NULL,'Active','CAPA Initiation and Investigation','Initiation of Corrective and Preventive Action for non-conformances, deviations, complaints, or audit findings.',NULL,NULL,'Document: problem description, immediate containment actions, investigation team assignment, timeline for completion. Use root cause analysis tools (5-Whys, fishbone, etc.).','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,183,NULL,NULL,NULL,4),(188,'step',NULL,'Active','CAPA Implementation and Effectiveness Check','Implementation of corrective and preventive actions and verification of effectiveness.',NULL,NULL,'Implement: corrective actions (address immediate problem), preventive actions (prevent recurrence). Monitor effectiveness. Close CAPA when verified effective.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,183,NULL,NULL,NULL,5),(189,'process',NULL,'Active','Audit Management','Comprehensive audit management system for internal audits, external supplier audits, and regulatory inspections (FDA, EMA, HPRA).',NULL,NULL,'Maintains audit schedule, tracks findings, manages corrective actions, and ensures inspection readiness. Critical for maintaining GMP compliance and market authorization.','2025-11-24 21:07:13','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(190,'step',NULL,'Active','Internal Audit Program','Scheduled internal audits of all GMP areas including manufacturing, quality control, warehouse, documentation, and computer systems.',NULL,NULL,'Annual audit schedule. Areas audited: manufacturing processes, QC laboratories, warehouse operations, documentation systems, validation, training records. Use risk-based approach.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,189,NULL,NULL,NULL,1),(191,'step',NULL,'Active','Supplier/Vendor Audit','Audit of critical suppliers and vendors including API manufacturers, excipient suppliers, packaging material suppliers, and contract manufacturers.',NULL,NULL,'Audit frequency based on risk: critical suppliers annually, others biennially. Assess: GMP compliance, quality systems, change control, deviation management, supply reliability.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,189,NULL,NULL,NULL,2),(192,'step',NULL,'Active','Regulatory Inspection Management','Preparation, management, and follow-up of regulatory inspections (FDA, EMA, HPRA, MHRA, etc.).',NULL,NULL,'Pre-inspection: readiness assessment, document organization, team briefing. During: escort, document requests, responses. Post-inspection: response to findings, corrective actions, follow-up.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,189,NULL,NULL,NULL,3),(193,'step',NULL,'Active','Audit Finding Management','Systematic management of audit findings including classification, root cause analysis, corrective action planning, and closure verification.',NULL,NULL,'Classify findings: critical, major, minor. Document: finding description, root cause, impact assessment, corrective action plan, timeline, responsible party. Track to closure.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,189,NULL,NULL,NULL,4),(194,'process',NULL,'Active','Analytical Method Validation and OOS Handling','Comprehensive system for analytical method validation per ICH Q2(R1) and systematic handling of Out-of-Specification (OOS) and Out-of-Trend (OOT) results.',NULL,NULL,'All analytical methods must be validated before use. OOS results require formal investigation per FDA OOS Guidance. Maintains data integrity and ensures reliable test results.','2025-11-24 21:07:13','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(195,'step',NULL,'Active','Method Development and Optimization','Development and optimization of analytical methods for drug substance and drug product testing.',NULL,NULL,'Develop: HPLC, GC, dissolution, particle size, microbial methods. Optimize: column selection, mobile phase, detection wavelength, sample preparation. Document development work.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,194,NULL,NULL,NULL,1),(196,'step',NULL,'Active','Method Validation per ICH Q2(R1)','Comprehensive validation of analytical methods including specificity, accuracy, precision, linearity, range, LOD, LOQ, and robustness.',NULL,NULL,'Validation parameters: specificity (forced degradation), accuracy (recovery 98-102%), precision (RSD <2%), linearity (R² >0.99), range, LOD/LOQ, robustness. Document in validation report.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,194,NULL,NULL,NULL,2),(197,'step',NULL,'Active','OOS Investigation Phase 1: Laboratory Investigation','Initial laboratory investigation of OOS results including analyst interview, sample preparation review, and instrument check.',NULL,NULL,'Within 1 business day. Check: calculation errors, sample preparation errors, instrument malfunction, analyst technique. Document all findings. If no assignable cause, proceed to Phase 2.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,194,NULL,NULL,NULL,3),(198,'step',NULL,'Active','OOS Investigation Phase 2: Full Investigation','Comprehensive investigation including retest, resample, and root cause analysis if Phase 1 inconclusive.',NULL,NULL,'Retest: original sample (if available), resample from batch. Root cause analysis: review manufacturing process, review method, review equipment. Determine if batch is out of specification.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,194,NULL,NULL,NULL,4),(199,'step',NULL,'Active','OOS Investigation Phase 3: Batch Disposition','Final decision on batch disposition based on investigation findings and risk assessment.',NULL,NULL,'If assignable cause found: invalidate original result, use retest results. If no assignable cause: batch fails specification, investigate manufacturing process. Document decision and rationale.','2025-11-24 21:07:13','2025-11-24 21:07:13',NULL,NULL,194,NULL,NULL,NULL,5),(200,'process',NULL,'Active','Packaging Material Specification and Sourcing','Development and management of packaging material specifications including primary packaging (blisters, canisters), secondary packaging (cartons), and tertiary packaging (shippers). Includes supplier qualification and material testing.',NULL,NULL,'All packaging materials must meet regulatory requirements and protect product integrity. Specifications include: dimensions, materials of construction, barrier properties, compatibility testing, supplier qualification.','2025-11-24 21:07:42','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(201,'step',NULL,'Active','Primary Packaging Specification','Development of specifications for primary packaging components (blisters for DPI, canisters for MDI, valves, actuators).',NULL,NULL,'Specifications: dimensions, materials (aluminum, plastic grades), barrier properties (moisture, oxygen), compatibility with drug product, regulatory compliance (Ph.Eur., USP).','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,200,NULL,NULL,NULL,1),(202,'step',NULL,'Active','Secondary Packaging Specification','Development of specifications for secondary packaging (cartons, leaflets, labels).',NULL,NULL,'Specifications: dimensions, materials, print quality, regulatory text requirements, child-resistant features (if required), tamper-evident features.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,200,NULL,NULL,NULL,2),(203,'step',NULL,'Active','Packaging Material Testing and Qualification','Testing and qualification of packaging materials including compatibility studies, barrier testing, and stability studies.',NULL,NULL,'Tests: extractables/leachables, moisture permeability, oxygen transmission, light protection, compatibility with drug product, stability in contact with product.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,200,NULL,NULL,NULL,3),(204,'process',NULL,'Active','Label Design and Regulatory Compliance','Complete label design process ensuring regulatory compliance with FDA, EMA, and local requirements. Includes artwork development, regulatory text review, and approval workflow.',NULL,NULL,'Labels must comply with: FDA 21 CFR Part 201, EU Directive 2001/83/EC, local country requirements. Includes: product name, active ingredient, strength, dosage, warnings, storage conditions, expiry, batch number.','2025-11-24 21:07:42','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(205,'step',NULL,'Active','Regulatory Text Development','Development of regulatory text for labels including indications, dosage, warnings, contraindications, and storage instructions.',NULL,NULL,'Text must be approved by Regulatory Affairs. Follow approved product information (SmPC, Package Insert). Ensure accuracy and completeness. Review for medical accuracy.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,204,NULL,NULL,NULL,1),(206,'step',NULL,'Active','Artwork Design and Layout','Graphic design of label artwork including layout, fonts, colors, and branding elements while maintaining regulatory compliance.',NULL,NULL,'Design considerations: readability, font size (minimum 7pt), color contrast, space for all required text, branding consistency. Use approved templates.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,204,NULL,NULL,NULL,2),(207,'step',NULL,'Active','Regulatory Review and Approval','Review of label artwork by Regulatory Affairs, Medical Affairs, and Quality Assurance for compliance and accuracy.',NULL,NULL,'Review: regulatory text accuracy, completeness, compliance with regulations, medical accuracy, readability. Obtain approvals before printing.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,204,NULL,NULL,NULL,3),(208,'step',NULL,'Active','Label Printing and Quality Control','Printing of labels with quality control checks including color matching, text accuracy, barcode verification, and print quality.',NULL,NULL,'Print per approved artwork. QC checks: text accuracy, color match, barcode readability, print quality, dimensions. Document print batch information.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,204,NULL,NULL,NULL,4),(209,'process',NULL,'Active','Serialization and Anti-Counterfeiting','Implementation of serialization and track-and-trace systems to prevent counterfeiting and ensure product authenticity. Includes unique identifiers (GTIN, serial numbers), barcodes, and data submission to regulatory databases.',NULL,NULL,'Required by: EU FMD (Falsified Medicines Directive), US DSCSA (Drug Supply Chain Security Act). Serialization: unique serial number per unit, aggregation (carton to case), data submission to national databases.','2025-11-24 21:07:42','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(210,'step',NULL,'Active','Serial Number Generation and Assignment','Generation and assignment of unique serial numbers to each product unit following GS1 standards.',NULL,NULL,'Format: GTIN (14 digits) + Serial Number (variable length). Ensure uniqueness. Generate in secure system. Maintain serial number database.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,209,NULL,NULL,NULL,1),(211,'step',NULL,'Active','Barcode Printing and Verification','Printing of 2D DataMatrix or QR codes on product labels and verification of code quality and readability.',NULL,NULL,'Print codes per GS1 standards. Verify: code quality (grade A or B), readability by scanners, data accuracy. 100% verification required.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,209,NULL,NULL,NULL,2),(212,'step',NULL,'Active','Aggregation and Parent-Child Relationships','Establishment of parent-child relationships (unit to carton, carton to case) for supply chain tracking.',NULL,NULL,'Aggregate: units into cartons, cartons into cases. Maintain parent-child relationships in database. Enable de-aggregation for returns/recalls.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,209,NULL,NULL,NULL,3),(213,'step',NULL,'Active','Data Submission to Regulatory Databases','Submission of serialization data to national regulatory databases (EMVO for EU, FDA for US) for product authentication.',NULL,NULL,'Submit: product information, serial numbers, batch numbers, expiry dates, aggregation data. Submit before product release. Maintain data accuracy and completeness.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,209,NULL,NULL,NULL,4),(214,'process',NULL,'Active','Batch Packaging and Labeling Workflow','Complete packaging and labeling workflow for production batches including line setup, packaging operations, in-process controls, and documentation.',NULL,NULL,'Performed under GMP conditions. Includes: line clearance, material verification, packaging operations, label application, in-process checks, batch documentation, line clearance after completion.','2025-11-24 21:07:42','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(215,'step',NULL,'Active','Packaging Line Setup and Clearance','Setup and clearance of packaging line including equipment cleaning, material verification, and line clearance documentation.',NULL,NULL,'Clear previous batch. Verify: equipment clean, correct materials, correct batch number, line clearance documented. QA approval required before start.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,214,NULL,NULL,NULL,1),(216,'step',NULL,'Active','Primary Packaging Operations','Primary packaging operations including filling product into primary containers (blisters, canisters) and sealing.',NULL,NULL,'Operations: product filling, container sealing, leak testing (if applicable), visual inspection. Document: quantities, line speed, operator, timestamps.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,214,NULL,NULL,NULL,2),(217,'step',NULL,'Active','Labeling Operations','Application of labels to primary containers including label verification, application, and quality checks.',NULL,NULL,'Verify: correct label, correct batch number, expiry date, serial numbers. Apply labels. Check: alignment, adhesion, readability. Document label batch information.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,214,NULL,NULL,NULL,3),(218,'step',NULL,'Active','Secondary Packaging Operations','Secondary packaging operations including cartoning, leaflet insertion, and case packing.',NULL,NULL,'Operations: carton erection, leaflet insertion, carton closing, case packing, palletizing. Verify: correct carton, correct leaflet, correct quantities.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,214,NULL,NULL,NULL,4),(219,'step',NULL,'Active','In-Process Controls and Sampling','In-process quality controls during packaging including visual inspection, label verification, and sampling for testing.',NULL,NULL,'Controls: label accuracy checks, visual inspection, weight checks, barcode verification, sampling for retain samples. Document all controls and results.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,214,NULL,NULL,NULL,5),(220,'process',NULL,'Active','Finished Goods Release','Final release of finished goods after completion of packaging, labeling, and all quality checks. Includes batch record review, test result review, and release authorization.',NULL,NULL,'Release by Qualified Person (EU) or authorized person (US). All requirements must be met: manufacturing complete, packaging complete, all tests passed, documentation complete, no critical deviations.','2025-11-24 21:07:42','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(221,'step',NULL,'Active','Packaging Batch Record Review','Review of packaging batch records for completeness, accuracy, and compliance.',NULL,NULL,'Review: material reconciliation, packaging operations, label application, in-process controls, deviations, operator signatures. Verify completeness and accuracy.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,220,NULL,NULL,NULL,1),(222,'step',NULL,'Active','Final Quality Check','Final quality check including retain sample inspection, label verification, and packaging integrity check.',NULL,NULL,'Check: retain samples, label accuracy, packaging integrity, serialization data, aggregation data. Document all checks.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,220,NULL,NULL,NULL,2),(223,'step',NULL,'Active','Release Authorization','Final release authorization by Qualified Person or authorized person after all requirements met.',NULL,NULL,'Authorize release: sign batch record, issue release certificate, update system status. Release only if all requirements met. Document release decision.','2025-11-24 21:07:42','2025-11-24 21:07:42',NULL,NULL,220,NULL,NULL,NULL,3),(224,'process',NULL,'Active','Vendor and Material Qualification','Comprehensive vendor qualification process including supplier assessment, material qualification, quality agreements, and ongoing supplier management.',NULL,NULL,'Critical suppliers: API manufacturers, excipient suppliers, packaging material suppliers. Qualification includes: GMP audit, quality system assessment, material testing, quality agreement execution.','2025-11-24 21:07:55','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(225,'step',NULL,'Active','Supplier Assessment and Selection','Initial assessment and selection of potential suppliers including capability assessment, quality system review, and financial stability check.',NULL,NULL,'Assess: manufacturing capabilities, quality systems, regulatory compliance, financial stability, supply reliability, technical support. Use supplier questionnaire and site visits.','2025-11-24 21:07:55','2025-11-24 21:07:55',NULL,NULL,224,NULL,NULL,NULL,1),(226,'step',NULL,'Active','Supplier Audit and Qualification','Formal GMP audit of supplier facilities and quality systems to assess compliance and capability.',NULL,NULL,'Audit scope: manufacturing facilities, quality systems, documentation, change control, deviation management, training. Document findings. Require corrective actions if needed.','2025-11-24 21:07:55','2025-11-24 21:07:55',NULL,NULL,224,NULL,NULL,NULL,2),(227,'step',NULL,'Active','Material Qualification and Testing','Qualification of materials from supplier including identity testing, specification verification, and compatibility studies.',NULL,NULL,'Test: identity, purity, particle size (if applicable), microbial limits, endotoxins. Verify against specifications. Perform compatibility studies if needed.','2025-11-24 21:07:55','2025-11-24 21:07:55',NULL,NULL,224,NULL,NULL,NULL,3),(228,'step',NULL,'Active','Quality Agreement Execution','Execution of quality agreement defining responsibilities, specifications, testing requirements, and change control procedures.',NULL,NULL,'Agreement includes: material specifications, testing requirements, change control procedures, deviation reporting, audit rights, recall procedures. Legal review required.','2025-11-24 21:07:55','2025-11-24 21:07:55',NULL,NULL,224,NULL,NULL,NULL,4),(229,'process',NULL,'Active','Warehouse Operations and Stock Control','Complete warehouse management system including material receipt, storage, inventory control, stock rotation (FIFO/FEFO), and material issue to production.',NULL,NULL,'Warehouse must maintain: controlled storage conditions, accurate inventory records, proper segregation, security, traceability. Follow GMP requirements for storage and handling.','2025-11-24 21:07:55','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(230,'step',NULL,'Active','Material Receipt and Verification','Receipt of materials from suppliers including verification of delivery, documentation check, and initial inspection.',NULL,NULL,'Verify: delivery matches purchase order, documentation complete (COA, delivery note), container integrity, labeling. Document receipt. Quarantine until QC release.','2025-11-24 21:07:56','2025-11-24 21:07:56',NULL,NULL,229,NULL,NULL,NULL,1),(231,'step',NULL,'Active','Quarantine and QC Release','Quarantine of materials pending quality control testing and release to production use.',NULL,NULL,'Store in quarantine area. Await QC testing and release. Move to approved storage after release. Document quarantine and release dates.','2025-11-24 21:07:56','2025-11-24 21:07:56',NULL,NULL,229,NULL,NULL,NULL,2),(232,'step',NULL,'Active','Storage and Inventory Management','Storage of approved materials under controlled conditions with accurate inventory tracking and stock rotation.',NULL,NULL,'Storage: controlled temperature/humidity, proper segregation, security, FIFO/FEFO rotation. Inventory: accurate records, regular cycle counts, reconciliation. Monitor expiry dates.','2025-11-24 21:07:56','2025-11-24 21:07:56',NULL,NULL,229,NULL,NULL,NULL,3),(233,'step',NULL,'Active','Material Issue to Production','Issue of materials to production following approved procedures including material verification and documentation.',NULL,NULL,'Verify: material approved, within expiry, correct material, correct quantity. Issue per production order. Document issue. Update inventory records.','2025-11-24 21:07:56','2025-11-24 21:07:56',NULL,NULL,229,NULL,NULL,NULL,4),(234,'process',NULL,'Active','Transportation and Distribution Tracking','Complete distribution management including transportation arrangements, shipment tracking, delivery verification, and distribution records.',NULL,NULL,'Track: shipment status, delivery dates, temperature monitoring (if applicable), security, customs clearance (if international). Maintain distribution records for regulatory inspection.','2025-11-24 21:07:56','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(235,'step',NULL,'Active','Shipment Planning and Coordination','Planning and coordination of product shipments including carrier selection, route planning, and documentation preparation.',NULL,NULL,'Plan: shipment dates, carrier selection, route optimization, documentation (commercial invoice, packing list, certificates). Coordinate with customers and carriers.','2025-11-24 21:07:56','2025-11-24 21:07:56',NULL,NULL,234,NULL,NULL,NULL,1),(236,'step',NULL,'Active','Shipment Execution and Tracking','Execution of shipments with real-time tracking and monitoring of shipment status and conditions.',NULL,NULL,'Execute: prepare shipment, load product, dispatch, track in transit. Monitor: location, temperature (if applicable), delivery status. Update tracking system.','2025-11-24 21:07:56','2025-11-24 21:07:56',NULL,NULL,234,NULL,NULL,NULL,2),(237,'step',NULL,'Active','Delivery Verification and Documentation','Verification of delivery including proof of delivery, condition check, and documentation of any issues.',NULL,NULL,'Verify: delivery complete, product condition, temperature records (if applicable), documentation complete. Document any damage or discrepancies. Obtain POD.','2025-11-24 21:07:56','2025-11-24 21:07:56',NULL,NULL,234,NULL,NULL,NULL,3),(238,'process',NULL,'Active','Cold Chain Management','Management of temperature-controlled supply chain for products requiring cold storage (2-8°C) or frozen storage (-20°C). Includes temperature monitoring, validation, and deviation handling.',NULL,NULL,'Critical for biologics, vaccines, and temperature-sensitive products. Requires: validated cold storage, temperature monitoring during transport, qualified packaging, deviation procedures.','2025-11-24 21:07:56','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(239,'step',NULL,'Active','Cold Storage Validation','Validation of cold storage facilities and transport systems to ensure temperature control within specified ranges.',NULL,NULL,'Validate: storage facilities, transport vehicles, packaging systems. Temperature mapping studies. Establish temperature limits and monitoring procedures.','2025-11-24 21:07:56','2025-11-24 21:07:56',NULL,NULL,238,NULL,NULL,NULL,1),(240,'step',NULL,'Active','Temperature Monitoring and Control','Continuous temperature monitoring during storage and transport using data loggers and monitoring systems.',NULL,NULL,'Monitor: storage temperature, transport temperature, temperature excursions. Use calibrated data loggers. Review temperature records. Alert on excursions.','2025-11-24 21:07:56','2025-11-24 21:07:56',NULL,NULL,238,NULL,NULL,NULL,2),(241,'step',NULL,'Active','Temperature Excursion Handling','Investigation and handling of temperature excursions including impact assessment and product disposition.',NULL,NULL,'Investigate: duration, magnitude, product impact. Assess: stability data, product quality impact. Decide: use product, quarantine, reject. Document investigation and decision.','2025-11-24 21:07:56','2025-11-24 21:07:56',NULL,NULL,238,NULL,NULL,NULL,3),(242,'process',NULL,'Active','Recall Management','Comprehensive recall management system for product recalls including recall initiation, classification, execution, effectiveness checks, and regulatory reporting.',NULL,NULL,'Recalls classified: Class I (life-threatening), Class II (serious), Class III (minor). Must notify regulatory authorities. Track recall effectiveness. Document all activities.','2025-11-24 21:07:56','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(243,'step',NULL,'Active','Recall Initiation and Classification','Initiation of recall process including problem identification, risk assessment, and recall classification (Class I, II, or III).',NULL,NULL,'Initiate: identify problem, assess risk, classify recall, notify management. Classify per FDA/EMA guidance. Document initiation and rationale.','2025-11-24 21:07:56','2025-11-24 21:07:56',NULL,NULL,242,NULL,NULL,NULL,1),(244,'step',NULL,'Active','Regulatory Notification','Notification of regulatory authorities (FDA, EMA, etc.) of recall including recall strategy and communication plan.',NULL,NULL,'Notify: within 24 hours for Class I, within 48 hours for Class II. Submit: recall notification, recall strategy, communication materials. Coordinate with regulatory affairs.','2025-11-24 21:07:56','2025-11-24 21:07:56',NULL,NULL,242,NULL,NULL,NULL,2),(245,'step',NULL,'Active','Recall Execution','Execution of recall including customer notification, product retrieval, and quarantine of recalled product.',NULL,NULL,'Execute: notify customers, retrieve product, quarantine recalled product, track retrieval effectiveness. Use distribution records to identify customers. Document all activities.','2025-11-24 21:07:56','2025-11-24 21:07:56',NULL,NULL,242,NULL,NULL,NULL,3),(246,'step',NULL,'Active','Recall Effectiveness Check','Verification of recall effectiveness including retrieval rate calculation and assessment of recall completeness.',NULL,NULL,'Calculate: retrieval rate, effectiveness. Assess: completeness of retrieval, remaining product in market. Report effectiveness to regulatory authorities. Close recall when complete.','2025-11-24 21:07:56','2025-11-24 21:07:56',NULL,NULL,242,NULL,NULL,NULL,4),(247,'process',NULL,'Active','Preventive and Corrective Maintenance','Comprehensive maintenance management system including scheduled preventive maintenance, unscheduled corrective maintenance, maintenance planning, and equipment reliability tracking.',NULL,NULL,'Maintenance critical for: GMP compliance, product quality, equipment reliability, production efficiency. Includes: maintenance schedules, work orders, spare parts management, maintenance history, downtime tracking.','2025-11-24 21:08:10','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(248,'step',NULL,'Active','Maintenance Schedule Development','Development of preventive maintenance schedules based on equipment criticality, manufacturer recommendations, and historical data.',NULL,NULL,'Schedule: daily, weekly, monthly, quarterly, annual tasks. Based on: manufacturer recommendations, risk assessment, historical failure data. Document in maintenance plan.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,247,NULL,NULL,NULL,1),(249,'step',NULL,'Active','Preventive Maintenance Execution','Execution of scheduled preventive maintenance tasks including lubrication, cleaning, inspection, and parts replacement.',NULL,NULL,'Execute per schedule. Tasks: cleaning, lubrication, inspection, calibration, parts replacement, testing. Document: work performed, parts used, findings, completion date, technician.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,247,NULL,NULL,NULL,2),(250,'step',NULL,'Active','Corrective Maintenance and Troubleshooting','Response to equipment failures including troubleshooting, repair, and return to service verification.',NULL,NULL,'Respond: identify problem, troubleshoot, repair, test, return to service. Document: failure description, root cause, repair actions, parts used, verification testing.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,247,NULL,NULL,NULL,3),(251,'step',NULL,'Active','Maintenance Documentation and History','Documentation of all maintenance activities including work orders, maintenance logs, and equipment history.',NULL,NULL,'Document: work orders, maintenance logs, parts usage, downtime, findings, recommendations. Maintain equipment history file. Track: MTBF, MTTR, maintenance costs.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,247,NULL,NULL,NULL,4),(252,'process',NULL,'Active','Equipment Calibration Management','Comprehensive calibration management system for all measuring and testing equipment including calibration schedules, calibration execution, and calibration records.',NULL,NULL,'All critical equipment must be calibrated. Calibration: against traceable standards, at defined intervals, by qualified personnel. Document: calibration certificates, calibration history, out-of-calibration handling.','2025-11-24 21:08:10','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(253,'step',NULL,'Active','Calibration Schedule Development','Development of calibration schedules based on equipment criticality, manufacturer recommendations, and regulatory requirements.',NULL,NULL,'Schedule: critical equipment annually, others biennially or per manufacturer. Based on: equipment criticality, usage frequency, historical drift data. Document in calibration plan.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,252,NULL,NULL,NULL,1),(254,'step',NULL,'Active','Calibration Execution','Execution of calibration using traceable standards and documented procedures.',NULL,NULL,'Execute: use traceable standards (NIST, NPL), follow documented procedures, perform at multiple points, document results, apply calibration labels. Outsource to accredited labs if needed.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,252,NULL,NULL,NULL,2),(255,'step',NULL,'Active','Calibration Verification and Documentation','Verification of calibration results and documentation of calibration certificates and history.',NULL,NULL,'Verify: results within tolerance, certificate complete, traceability documented. Document: calibration certificate, calibration history, next due date. Update equipment status.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,252,NULL,NULL,NULL,3),(256,'step',NULL,'Active','Out-of-Calibration Handling','Investigation and handling of out-of-calibration equipment including impact assessment and product review.',NULL,NULL,'Investigate: when out of calibration, impact on products tested, root cause. Assess: product impact, need for retest. Document: investigation, corrective actions, product disposition.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,252,NULL,NULL,NULL,4),(257,'process',NULL,'Active','Downtime and Uptime Tracking','Systematic tracking of equipment downtime and uptime for production planning, reliability analysis, and continuous improvement.',NULL,NULL,'Track: downtime events, downtime duration, downtime causes, uptime percentage, MTBF (Mean Time Between Failures), MTTR (Mean Time To Repair). Use for: production planning, reliability improvement, maintenance optimization.','2025-11-24 21:08:10','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(258,'step',NULL,'Active','Downtime Event Recording','Recording of equipment downtime events including start time, end time, cause, and impact.',NULL,NULL,'Record: equipment, start time, end time, cause (breakdown, maintenance, changeover, etc.), impact on production, operator, maintenance technician. Use downtime tracking system.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,257,NULL,NULL,NULL,1),(259,'step',NULL,'Active','Downtime Analysis and Reporting','Analysis of downtime data including trend analysis, root cause analysis, and downtime reports.',NULL,NULL,'Analyze: downtime trends, common causes, equipment reliability, production impact. Report: monthly downtime summary, equipment performance, recommendations for improvement.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,257,NULL,NULL,NULL,2),(260,'step',NULL,'Active','Uptime Calculation and OEE','Calculation of equipment uptime, availability, and Overall Equipment Effectiveness (OEE).',NULL,NULL,'Calculate: uptime percentage, availability, OEE (availability × performance × quality). Target: >95% uptime, >85% OEE. Use for: performance monitoring, improvement initiatives.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,257,NULL,NULL,NULL,3),(261,'process',NULL,'Active','Spare Parts Inventory Management','Management of spare parts inventory including parts identification, stock levels, procurement, storage, and usage tracking.',NULL,NULL,'Maintain: critical spare parts inventory, minimum stock levels, parts database, supplier information, parts usage history. Ensure: parts availability for maintenance, cost optimization, obsolete parts management.','2025-11-24 21:08:10','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(262,'step',NULL,'Active','Spare Parts Identification and Cataloging','Identification and cataloging of spare parts including part numbers, descriptions, and equipment associations.',NULL,NULL,'Identify: critical spare parts, part numbers, suppliers, lead times, costs. Catalog: part numbers, descriptions, equipment associations, specifications. Maintain parts database.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,261,NULL,NULL,NULL,1),(263,'step',NULL,'Active','Stock Level Management','Management of spare parts stock levels including minimum/maximum levels, reorder points, and inventory optimization.',NULL,NULL,'Set: minimum stock levels, reorder points, maximum stock levels. Based on: usage history, lead times, criticality, cost. Monitor: stock levels, usage rates, reorder when needed.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,261,NULL,NULL,NULL,2),(264,'step',NULL,'Active','Parts Procurement and Receipt','Procurement and receipt of spare parts including purchase orders, supplier coordination, and receipt verification.',NULL,NULL,'Procure: issue purchase orders, coordinate with suppliers, track delivery, receive parts, verify against order, update inventory. Document: purchase orders, delivery notes, receipts.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,261,NULL,NULL,NULL,3),(265,'step',NULL,'Active','Parts Usage and Tracking','Tracking of spare parts usage including issue to maintenance, usage recording, and inventory updates.',NULL,NULL,'Issue: parts to maintenance work orders, record usage, update inventory, track usage history. Document: parts issued, work order, date, technician. Analyze: usage patterns, costs.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,261,NULL,NULL,NULL,4),(266,'process',NULL,'Active','Equipment Qualification','Comprehensive equipment qualification process including Design Qualification (DQ), Installation Qualification (IQ), Operational Qualification (OQ), and Performance Qualification (PQ).',NULL,NULL,'Qualification required for: GMP equipment, critical process equipment, analytical instruments. Follows: ICH Q7, FDA Process Validation Guidance. Documents: DQ, IQ, OQ, PQ protocols and reports.','2025-11-24 21:08:10','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(267,'step',NULL,'Active','Design Qualification (DQ)','Verification that equipment design meets user requirements and regulatory requirements.',NULL,NULL,'Verify: design meets URS (User Requirements Specification), regulatory compliance, GMP requirements. Document: design review, design approval, design qualification report.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,266,NULL,NULL,NULL,1),(268,'step',NULL,'Active','Installation Qualification (IQ)','Verification that equipment is installed correctly according to specifications and manufacturer requirements.',NULL,NULL,'Verify: equipment received as specified, installed correctly, utilities connected, documentation received. Document: installation checklist, installation report, as-built drawings.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,266,NULL,NULL,NULL,2),(269,'step',NULL,'Active','Operational Qualification (OQ)','Verification that equipment operates correctly across all operating ranges and functions as intended.',NULL,NULL,'Test: all functions, operating ranges, alarms, safety features. Document: test protocols, test results, OQ report. Verify: equipment operates per specifications.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,266,NULL,NULL,NULL,3),(270,'step',NULL,'Active','Performance Qualification (PQ)','Verification that equipment performs consistently under actual operating conditions with actual product.',NULL,NULL,'Test: performance under actual conditions, consistency, reliability. Document: PQ protocol, test results, PQ report. Verify: equipment meets performance requirements.','2025-11-24 21:08:10','2025-11-24 21:08:10',NULL,NULL,266,NULL,NULL,NULL,4),(271,'process',NULL,'Active','Risk Assessment Workflow','Comprehensive risk assessment system using various methodologies (HAZOP, 5-Whys, Job Safety Analysis, FMEA) to identify, assess, and control workplace hazards.',NULL,NULL,'Risk assessments required for: new processes, equipment changes, work activities, chemical handling. Methods: HAZOP (Hazard and Operability Study), 5-Whys, JSA (Job Safety Analysis), FMEA (Failure Mode and Effects Analysis).','2025-11-24 21:08:23','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(272,'step',NULL,'Active','HAZOP Study','Hazard and Operability Study for systematic identification of hazards and operability problems in processes and equipment.',NULL,NULL,'Method: guideword approach (no flow, more flow, less pressure, etc.). Team: process engineer, operator, EHS, maintenance. Document: HAZOP worksheet, recommendations, action items.','2025-11-24 21:08:23','2025-11-24 21:08:23',NULL,NULL,271,NULL,NULL,NULL,1),(273,'step',NULL,'Active','5-Whys Root Cause Analysis','Systematic root cause analysis using 5-Whys methodology to identify underlying causes of incidents or hazards.',NULL,NULL,'Method: ask \"why\" five times to identify root cause. Document: problem statement, why questions, root cause, corrective actions. Use for: incident investigation, problem solving.','2025-11-24 21:08:23','2025-11-24 21:08:23',NULL,NULL,271,NULL,NULL,NULL,2),(274,'step',NULL,'Active','Job Safety Analysis (JSA)','Job Safety Analysis to identify hazards associated with specific work tasks and develop safe work procedures.',NULL,NULL,'Steps: break down job into steps, identify hazards for each step, develop controls, document safe work procedure. Review: with workers, update as needed, train workers.','2025-11-24 21:08:23','2025-11-24 21:08:23',NULL,NULL,271,NULL,NULL,NULL,3),(275,'step',NULL,'Active','Risk Control and Mitigation','Implementation of risk controls and mitigation measures based on risk assessment findings.',NULL,NULL,'Hierarchy: eliminate, substitute, engineering controls, administrative controls, PPE. Implement: controls per risk assessment, verify effectiveness, document implementation.','2025-11-24 21:08:23','2025-11-24 21:08:23',NULL,NULL,271,NULL,NULL,NULL,4),(276,'process',NULL,'Active','Incident Reporting and Investigation','Comprehensive incident management system including incident reporting, investigation, root cause analysis, corrective actions, and regulatory reporting (RIDDOR, OSHA).',NULL,NULL,'Incidents: injuries, near misses, property damage, environmental releases. Report: immediately for serious incidents, within 24 hours for others. Investigate: all incidents, identify root causes, implement corrective actions.','2025-11-24 21:08:23','2025-12-08 18:11:14',NULL,NULL,356,NULL,NULL,NULL,0),(277,'step',NULL,'Active','Incident Reporting','Immediate reporting of incidents including injury, near miss, property damage, or environmental release.',NULL,NULL,'Report: immediately to supervisor, EHS department, management. Document: incident report form, witness statements, photographs, initial assessment. Classify: severity, type.','2025-11-24 21:08:23','2025-11-24 21:08:23',NULL,NULL,276,NULL,NULL,NULL,1),(278,'step',NULL,'Active','Incident Investigation','Comprehensive investigation of incidents including fact gathering, witness interviews, and evidence collection.',NULL,NULL,'Investigate: within 24-48 hours, gather facts, interview witnesses, collect evidence, review procedures, identify contributing factors. Document: investigation report, timeline, findings.','2025-11-24 21:08:23','2025-11-24 21:08:23',NULL,NULL,276,NULL,NULL,NULL,2),(279,'step',NULL,'Active','Root Cause Analysis','Root cause analysis to identify underlying causes of incidents using appropriate methodologies.',NULL,NULL,'Methods: 5-Whys, fishbone diagram, fault tree analysis. Identify: immediate causes, contributing factors, root causes. Document: analysis, root causes identified.','2025-11-24 21:08:23','2025-11-24 21:08:23',NULL,NULL,276,NULL,NULL,NULL,3),(280,'step',NULL,'Active','Corrective Action Implementation','Development and implementation of corrective actions to prevent recurrence of incidents.',NULL,NULL,'Develop: corrective actions addressing root causes, preventive actions to prevent similar incidents. Implement: actions per plan, verify effectiveness, document implementation.','2025-11-24 21:08:23','2025-11-24 21:08:23',NULL,NULL,276,NULL,NULL,NULL,4),(281,'step',NULL,'Active','Regulatory Reporting','Reporting of reportable incidents to regulatory authorities (RIDDOR, OSHA) as required by regulations.',NULL,NULL,'Report: serious injuries, fatalities, dangerous occurrences per RIDDOR (UK) or OSHA (US). Submit: within required timeframe, complete forms, provide investigation findings. Coordinate with regulatory affairs.','2025-11-24 21:08:23','2025-11-24 21:08:23',NULL,NULL,276,NULL,NULL,NULL,5),(282,'process',NULL,'Active','Waste Management Tracking','Comprehensive waste management system including waste identification, classification, segregation, storage, treatment, and disposal tracking.',NULL,NULL,'Waste types: hazardous, non-hazardous, pharmaceutical, chemical, biological. Classify: per regulations (EPA, Environment Agency). Track: waste generation, storage, treatment, disposal. Maintain: waste manifests, disposal certificates.','2