INSERT INTO `quiz_questions` VALUES (1,14,'multiple_choice','What is the primary purpose of the EHS Audit Procedure?','The procedure verifies compliance with EHS policies and determines management system effectiveness.',2.00,1,1,'2025-09-26 10:02:20'),(2,14,'multiple_choice','Which ISO standards does this audit procedure cover?','The procedure covers ISO14001:2015, ISO45001:2018, and ISO50001:2018 requirements.',2.00,2,1,'2025-09-26 10:02:20'),(3,14,'multiple_choice','Who is responsible for preparing the annual internal audit schedule?','EHS and Facilities are responsible for preparing the annual internal audit schedule.',2.00,3,1,'2025-09-26 10:02:20'),(4,14,'multiple_choice','How often are energy operational audits conducted for each SEU?','Each Significant Energy Use (SEU) must be audited at least annually.',2.00,4,1,'2025-09-26 10:02:20'),(5,14,'multiple_choice','What should auditors document regarding previous corrective actions?','Auditors must verify that previous corrective actions have been effectively discharged.',2.00,5,1,'2025-09-26 10:02:20'),(6,14,'multiple_choice','What is the definition of an Operational Audit according to this procedure?','Operational audits examine SEU operations including usage, condition, and maintenance.',2.00,6,1,'2025-09-26 10:02:20'),(7,14,'multiple_choice','When can remote audits take place?','Remote audits may occur when the Lead Auditor cannot attend site in person.',2.00,7,1,'2025-09-26 10:02:20'),(8,14,'multiple_choice','What is the minimum passing score required for this training?','The procedure requires minimum 80% marks for successful completion.',2.00,8,1,'2025-09-26 10:02:20'),(19,51,'multiple_choice','Who has ultimate responsibility for environmental, health and safety within the organization?','The Site Director holds ultimate responsibility for EHS according to the Safety Statement.',2.00,1,1,'2025-09-26 10:50:36'),(20,51,'multiple_choice','What legislation requires employers to consider safety as a joint responsibility?','The Safety, Health and Welfare at Work Act, 2005 establishes joint responsibility.',2.00,2,1,'2025-09-26 10:50:36'),(21,51,'multiple_choice','When must new employees receive site EHS induction training?','Induction training must occur within 14 days of work commencement.',2.00,3,1,'2025-09-26 10:50:36'),(22,51,'multiple_choice','What is the speed limit on the Amneal Ireland site?','The site speed limit is 10 km/h as specified in site safety rules.',2.00,4,1,'2025-09-26 10:50:36'),(23,51,'multiple_choice','How often must emergency evacuation drills be carried out?','Fire drills must be conducted at intervals not exceeding 6 months.',2.00,5,1,'2025-09-26 10:50:36'),(24,51,'multiple_choice','What must contractors provide before being accepted on-site?','Contractors must provide insurance, safety statement, method statements, and training records.',2.00,6,1,'2025-09-26 10:50:36'),(25,51,'multiple_choice','What is the company policy regarding parking on site?','The company policy mandates reverse parking only for all vehicles.',2.00,7,1,'2025-09-26 10:50:36'),(26,51,'multiple_choice','How long are working time records retained under the Organisation of Working Time Act?','Records must be retained for at least 3 years from creation date.',2.00,8,1,'2025-09-26 10:50:36'),(27,51,'multiple_choice','What must a pregnant employee provide to their employer?','Pregnant employees must provide medical certificate confirming their condition.',2.00,9,1,'2025-09-26 10:50:36'),(28,51,'multiple_choice','Who is responsible for investigating accidents in their department?','Department supervisors/managers are responsible for accident investigations.',2.00,10,1,'2025-09-26 10:50:36'),(29,51,'multiple_choice','Who has ultimate responsibility for environmental, health and safety within the organization?','The Site Director holds ultimate responsibility for EHS according to the Safety Statement.',2.00,1,1,'2025-09-26 11:31:37'),(30,51,'multiple_choice','Who has ultimate responsibility for environmental, health and safety within the organization?','The Site Director holds ultimate responsibility for EHS according to the Safety Statement.',2.00,1,1,'2025-09-26 11:32:26'),(36,54,'multiple_choice','Who has ultimate responsibility for environmental, health and safety within the organization?','The Site Director holds ultimate responsibility for EHS according to the Safety Statement.',2.00,0,1,'2025-11-15 18:55:23'),(37,54,'multiple_choice','What legislation requires employers to consider safety as a joint responsibility?','The Safety, Health and Welfare at Work Act, 2005 establishes joint responsibility.',2.00,0,1,'2025-11-15 18:55:23'),(38,54,'multiple_choice','When must new employees receive site EHS induction training?','Induction training must occur within 14 days of work commencement.',2.00,0,1,'2025-11-15 18:55:23'),(39,54,'multiple_choice','What is the speed limit on the Amneal Ireland site?','The site speed limit is 10 km/h as specified in site safety rules.',2.00,0,1,'2025-11-15 18:55:23'),(40,54,'multiple_choice','How often must emergency evacuation drills be carried out?','Fire drills must be conducted at intervals not exceeding 6 months.',2.00,0,1,'2025-11-15 18:55:23'),(41,54,'multiple_choice','What must contractors provide before being accepted on-site?','Contractors must provide insurance, safety statement, method statements, and training records.',2.00,0,1,'2025-11-15 18:55:23'),(42,54,'multiple_choice','What is the company policy regarding parking on site?','The company policy mandates reverse parking only for all vehicles.',2.00,0,1,'2025-11-15 18:55:23'),(43,54,'multiple_choice','How long are working time records retained under the Organisation of Working Time Act?','Records must be retained for at least 3 years from creation date.',2.00,0,1,'2025-11-15 18:55:23'),(44,54,'multiple_choice','What must a pregnant employee provide to their employer?','Pregnant employees must provide medical certificate confirming their condition.'