INSERT INTO `risk_register` VALUES (1,'QR-001','Out of Specification (OOS) Test Results','Risk of OOS results in quality control testing leading to batch rejection, investigation delays, and potential product shortages.',1,NULL,'FMEA','2025-11-25',1,NULL,'Manufacturing','MDI',NULL,'Active','Medium','Quarterly',NULL,'Draft',NULL,NULL,1,NULL,'2025-11-25 05:28:34','2025-11-25 05:28:34',NULL),(2,'REG-001','Data Integrity Violations in Electronic Records','Risk of data integrity violations in electronic records and laboratory data management systems, leading to regulatory citations and product approval delays.',6,NULL,'Audit','2025-11-25',1,NULL,'All Stages',NULL,NULL,'Active','Medium','Quarterly',NULL,'Draft',NULL,NULL,1,NULL,'2025-11-25 05:28:34','2025-11-25 05:28:34',NULL),(3,'MFG-001','Critical Equipment Failure During Production','Risk of critical equipment failure during production runs leading to batch loss, production delays, and supply chain disruption.',3,NULL,'HAZOP','2025-11-25',1,NULL,'Manufacturing','DPI',NULL,'Active','Medium','Quarterly',NULL,'Draft',NULL,NULL,1,NULL,'2025-11-25 05:28:34','2025-11-25 05:28:34',NULL),(4,'QR-002','Particle Size Distribution (PSD) Variability','Risk of PSD variability leading to inconsistent aerodynamic performance and dose delivery failures in DPI products.',13,25,'FMEA','2025-11-25',1,NULL,'Manufacturing','DPI',NULL,'Active','Medium','Quarterly',NULL,'Draft',NULL,NULL,1,NULL,'2025-11-25 06:19:05','2025-11-25 06:19:05',NULL),(5,'QR-003','Formulation Stability Failures','Risk of chemical, physical, or microbiological stability failures during shelf life leading to product degradation and quality issues.',13,29,'FMEA','2025-11-25',1,NULL,'All Stages','All',NULL,'Active','Medium','Quarterly',NULL,'Draft',NULL,NULL,1,NULL,'2025-11-25 06:19:05','2025-11-25 06:19:05',NULL),(6,'QR-004','Sterility Failure in Aseptic Processing','Risk of sterility failures in aseptic manufacturing processes leading to product contamination and patie