DROP TABLE IF EXISTS `risk_reviews`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `risk_reviews` (
  `review_id` int(11) NOT NULL AUTO_INCREMENT,
  `risk_id` int(11) NOT NULL,
  `review_date` date NOT NULL,
  `review_type` enum('Scheduled','Ad Hoc','Triggered','Management Review','Regulatory Review') DEFAULT 'Scheduled',
  `review_outcome` enum('No Change','Risk Increased','Risk Decreased','Controls Added','Controls Modified','Risk Closed','Escalated') DEFAULT 'No Change',
  `action_items` text DEFAULT NULL COMMENT 'Action items from review',
  `review_approved_by` int(11) DEFAULT NULL COMMENT 'people_id FK',
  `review_approval_date` date DEFAULT NULL,
  `reviewer` int(11) NOT NULL COMMENT 'people_id FK',
  `risk_status` enum('Active','Closed','Escalated','Monitoring','Under Review') NOT NULL DEFAULT 'Active',
  `status_change_rationale` text DEFAULT NULL,
  `next_review_date` date DEFAULT NULL,
  `escalation_required` enum('Yes','No') NOT NULL DEFAULT 'No',
  `escalated_to` varchar(255) DEFAULT NULL COMMENT 'Management level or person',
  `review_notes` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`review_id`),
  KEY `idx_risk_id` (`risk_id`),
  KEY `idx_review_date` (`review_date`),
  KEY `idx_reviewer` (`reviewer`),
  KEY `idx_risk_status` (`risk_status`),
  KEY `idx_next_review_date` (`next_review_date`),
  KEY `idx_review_type` (`review_type`),
  KEY `idx_review_outcome` (`review_outcome`),
  KEY `risk_reviews_ibfk_approved_by` (`review_approved_by`),
  CONSTRAINT `risk_reviews_ibfk_approved_by` FOREIGN KEY (`review_approved_by`) REFERENCES `people` (`people_id`) ON DELETE SET NULL,
  CONSTRAINT `risk_reviews_ibfk_reviewer` FOREIGN KEY (`reviewer`) REFERENCES `people` (`people_id`),
  CONSTRAINT `risk_reviews_ibfk_risk` FOREIGN KEY (`risk_id`) REFERENCES `risk_register` (`risk_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
