INSERT INTO `risk_reviews` VALUES (4,1,'2025-11-25','Scheduled','No Change',NULL,NULL,NULL,1,'Active',NULL,'2026-02-23','No',NULL,'Risk remains active. Controls are effective. Continue monitoring.','2025-11-25 05:28:34','2025-11-25 05:28:34'),(5,2,'2025-11-25','Scheduled','No Change',NULL,NULL,NULL,1,'Active',NULL,'2026-05-24','No',NULL,'Data integrity controls implemented. Regular audits scheduled.','2025-11-25 05:28:34','2025-11-25 05:28:34'),(6,3,'2025-11-25','Scheduled','No Change',NULL,NULL,NULL,1,'Active',NULL,'2026-02-23','No',NULL,'Preventive maintenance program in place. Equipment reliability improved.','2025-11-25 05:28:34','2025-11-25 05:28:34'),(10,1,'2024-01-20','Scheduled','Controls Added','1. Implement enhanced cleaning procedures between batches\n2. Install additional isolation barriers\n3. Train operators on new procedures',3,'2024-01-22',2,'Active','Controls have been implemented to reduce contamination risk. Risk remains active but mitigated.','2024-04-20','No',NULL,'Initial review completed. Risk assessment updated with new control measures. Effectiveness to be monitored.','2025-12-03 21:07:20','2025-12-03 21:07:20'),(11,2,'2024-02-15','Management Review','No Change','1. Continue monitoring compliance metrics\n2. Schedule mock inspection preparation\n3. Review documentation systems',1,'2024-02-16',1,'Active','Risk status unchanged. Ongoing monitoring required.','2024-03-15','No',NULL,'Management review confirms risk remains critical. All compliance systems operational.','2025-12-03 21:07:20','2025-12-03 21:07:20'),(12,84,'2024-02-20','Triggered','Controls Modified','1. Upgrade spill containment systems\n2. Implement new material handling procedures\n3. Conduct emergency response training',1,'2024-02-22',2,'Active','Enhanced controls implemented following incident review.','2024-05-20','No',NULL,'Review triggered by near-miss incident. Additional controls implemented to prevent recurrence.','2025-12-03 21:07:20','2025-12-03 21:07:20');
